.sb-nav a,.sb-nav button{display:flex;align-items:center;gap:9px;padding:8px 9px;border-radius:7px;color:#4a4a6a;text-decoration:none;font-size:.85rem;font-weight:600;background:transparent;border:none;cursor:pointer;width:100%;text-align:left;font-family:'Syne',sans-serif;transition:background .15s,color .15s}
.sb-nav a:hover,.sb-nav button:hover{background:rgba(234,88,12,.08);color:var(--accent)}
.sb-divider{height:1px;background:var(--border);margin:6px 12px}
.sb-fork{display:flex;align-items:center;justify-content:center;gap:8px;margin:0 10px 10px;padding:10px 12px;background:linear-gradient(135deg,#ea580c,#c2410c);color:#fff;border:none;border-radius:8px;font-size:.82rem;font-weight:700;cursor:pointer;font-family:'Syne',sans-serif;box-shadow:0 2px 8px rgba(234,88,12,.25);transition:opacity .15s,transform .1s;width:calc(100% - 20px)}
.sb-fork:hover{opacity:.92;transform:translateY(-1px)}
.sb-ver{margin-top:auto;padding:16px 14px 20px;font-size:.65rem;color:var(--muted);font-family:'JetBrains Mono',monospace;opacity:.8;text-align:center;border-top:1px solid var(--border)}
.sb-react-wrap{padding:0 10px 6px}
.sb-react-btns{display:flex;gap:8px;padding:0 4px}
