/* ── Shell ── */
.shell{margin-left:var(--sw);display:flex;flex-direction:column;min-height:100vh}
.topbar{position:sticky;top:0;z-index:200;height:var(--th);background:var(--bg);border-bottom:1px solid var(--border);display:flex;align-items:center;gap:10px;padding:0 20px}
.tb-name{font-size:.92rem;font-weight:700;color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;flex:1;min-width:0}
.tb-badge{display:inline-flex;align-items:center;padding:2px 9px;border-radius:100px;background:rgba(5,150,105,.1);color:#059669;font-size:.62rem;font-weight:700;letter-spacing:.06em;text-transform:uppercase;white-space:nowrap;flex-shrink:0}
.tb-gap{flex:1}
.btn-ghost{display:inline-flex;align-items:center;gap:6px;padding:6px 14px;background:transparent;border:1px solid var(--border);border-radius:7px;color:#4a4a6a;font-family:'Syne',sans-serif;font-size:.79rem;font-weight:600;text-decoration:none;cursor:pointer;transition:border-color .15s,background .15s,color .15s;white-space:nowrap}
