.cc-lines{font-size:.63rem;color:var(--muted2);font-family:'JetBrains Mono',monospace;margin-right:6px}
.cc-copy{display:inline-flex;align-items:center;gap:4px;padding:3px 9px;background:transparent;border:1px solid var(--border);border-radius:5px;font-size:.65rem;font-weight:700;color:var(--muted);cursor:pointer;font-family:'Syne',sans-serif;transition:border-color .15s,color .15s,background .15s;white-space:nowrap;flex-shrink:0}
