.pv-iframe-wrap{position:relative;width:100%;height:400px;background:#fff}
.pv-iframe{width:100%;height:100%;border:none;display:block}
/* ── Fullscreen overlay ── */
.fs-overlay{display:none;position:fixed;inset:0;z-index:9999;flex-direction:column;background:#000}
.fs-overlay.active{display:flex}
.fs-bar{display:flex;align-items:center;gap:10px;padding:10px 16px;background:var(--bg);border-bottom:1px solid var(--border)}
.fs-title{font-size:.85rem;font-weight:700;color:var(--text);flex:1}
.fs-iframe{flex:1;border:none;width:100%}
/* ── Toast ── */
.toast{position:fixed;bottom:24px;right:24px;z-index:10000;background:var(--surface);border:1px solid var(--border);border-radius:10px;padding:13px 17px;box-shadow:0 8px 24px rgba(0,0,0,.1);display:flex;align-items:center;gap:10px;font-size:.82rem;font-weight:600;color:var(--text);opacity:0;transform:translateY(10px);transition:opacity .25s,transform .25s;pointer-events:none}
.toast.show{opacity:1;transform:translateY(0)}
.toast-icon{width:26px;height:26px;border-radius:50%;background:linear-gradient(135deg,#ea580c,#c2410c);display:flex;align-items:center;justify-content:center;color:#fff;font-size:.72rem;flex-shrink:0}
/* ── Editor tab bar (shown when project has multiple tabs) ── */
.editor-tab-bar{display:flex;gap:6px;flex-wrap:wrap;padding:12px 20px 0;border-bottom:1px solid var(--border);background:var(--bg)}
