   echo '<div class="shell">';
   echo '<div class="topbar">';
   echo '<span class="tb-name">' . esc_html( $project_name ) . '</span>';
   echo '<span class="tb-badge">Published</span>';
   echo '<span class="tb-gap"></span>';
   echo '<a href="https://pterocos.eu.org/app" class="btn-ghost"><i class="fas fa-code"></i> Open Editor</a>';
   echo '</div>';

   // ── Editor tab bar (only shown when there are multiple editor tabs) ──
   echo '<div class="content-wrap">';
   if ( count( $editor_tabs ) > 1 ) {
    echo '<div class="editor-tab-bar" id="mlp-editor-tab-bar">';
    foreach ( $editor_tabs as $ei => $et ) {
     $active_cls = $ei === 0 ? ' active' : '';
     echo '<button class="editor-tab-btn' . $active_cls . '" data-etab="' . $ei . '">'
        . esc_html( $et['emoji'] . ' ' . $et['title'] )
        . '</button>';
    }
    echo '</div>';
   }

   // ── Code grid: all three panels always visible ──
   echo '<div class="code-grid">';
   foreach ( $tabs as $i => $tab ) {
    $lang   = strtolower( $tab['lang'] );
    $color  = isset( $lang_colours[ $lang ] ) ? $lang_colours[ $lang ] : '#94a3b8';
    $lines  = max( 1, substr_count( $tab['content'], "\n" ) + 1 );
    echo '<div class="code-card">';
    echo '<div class="cc-header">';
    echo '<span class="cc-dot" style="background:' . esc_attr( $color ) . '"></span>';
    echo '<span class="cc-title">' . esc_html( $tab['name'] ) . '</span>';
    echo '<span class="cc-lines">' . $lines . ' line' . ( $lines !== 1 ? 's' : '' ) . '</span>';
    echo '<button class="cc-copy" data-card="' . $i . '"><i class="fas fa-copy"></i> Copy</button>';
    echo '</div>';
    echo '<div class="cc-body"><pre class="code-pre" id="code-pre-' . $i . '">' . esc_html( $tab['content'] ) . '</pre></div>';
    echo '</div>';
   }
   echo '</div>';

   // ── Live preview (Python: Pyodide WASM execution; HTML: srcdoc preview) ��─
   echo '<div class="preview-section">';
   echo '<div class="pv-header">';
   echo '<div class="pv-dots"><div class="pv-dot" style="background:#ef4444"></div><div class="pv-dot" style="background:#f59e0b"></div><div class="pv-dot" style="background:#10b981"></div></div>';
   echo '<span class="pv-title">' . ( $is_python ? 'Python Output' : ( $is_sql ? 'SQL Output' : ( $is_lua ? 'Lua Output' : ( $is_duckdb ? 'DuckDB Output' : ( $is_ruby ? 'Ruby Output' : ( $is_rust ? 'Rust Output' : ( $is_csharp ? 'C# Output' : ( $is_php ? 'PHP Output' : 'Live Preview' ) ) ) ) ) ) ) ) . '</span>';
   echo '<button class="pv-btn" id="mlp-fs-btn"><i class="fas fa-expand"></i> Fullscreen</button>';
   echo '<button class="pv-btn" id="mlp-refresh-btn" style="margin-left:6px"><i class="fas fa-sync-alt"></i> ' . ( ( $is_python || $is_sql || $is_lua || $is_duckdb || $is_ruby || $is_rust || $is_csharp ) ? 'Re-run' : ( $is_php ? 'Reload' : 'Refresh' ) ) . '</button>';
   echo '</div>';
   echo '<div class="pv-iframe-wrap"><iframe class="pv-iframe" id="mlp-preview-iframe" sandbox="allow-scripts allow-same-origin allow-forms allow-modals allow-popups"></iframe></div>';
   echo '</div>';

   echo '</div>';// content-wrap
   echo '</div>';// shell

   // ── Fullscreen overlay ──
   echo '<div class="fs-overlay" id="mlp-fs-overlay">';
   echo '<div class="fs-bar"><span class="fs-title">' . esc_html( $project_name ) . '</span>';
   echo '<button class="btn-ghost" id="mlp-fs-close"><i class="fas fa-compress"></i> Exit Fullscreen</button></div>';
   echo '<iframe class="fs-iframe" id="mlp-fs-iframe" sandbox="allow-scripts allow-same-origin allow-forms allow-modals allow-popups"></iframe>';
   echo '</div>';

   // ── Toast ──
   echo '<div class="toast" id="mlp-toast"><div class="toast-icon"><i class="fas fa-check"></i></div><span id="mlp-toast-msg"></span></div>';
   ?>
<script>
(function(){
  var TABS         = <?php echo $js_tabs; ?>;
  var EDITOR_TABS  = <?php echo $js_editor_tabs; ?>;
  var PROJ_NAME    = <?php echo $js_project_name; ?>;
  var TOKEN        = <?php echo $js_token; ?>;
  var PAYLOAD_RAW  = <?php echo $js_payload; ?>;
  var IS_PYTHON    = <?php echo $js_is_python; ?>;
  var IS_SQL       = <?php echo $js_is_sql; ?>;
  var IS_LUA       = <?php echo $js_is_lua; ?>;
  var IS_DUCKDB    = <?php echo $js_is_duckdb; ?>;
  var IS_RUBY      = <?php echo $js_is_ruby; ?>;
  var IS_RUST      = <?php echo $js_is_rust; ?>;
  var RUST_CHANNEL = <?php echo $js_rust_channel; ?>;
  var IS_CSHARP    = <?php echo $js_is_csharp; ?>;
  var IS_PHP          = <?php echo $js_is_php; ?>;
  var PHP_OUTPUT      = <?php echo $js_php_output; ?>;
  var PHP_OUT_IS_HTML = <?php echo $js_php_out_html; ?>;
  var PHP_OUT_AT      = <?php echo $js_php_out_at; ?>;
  var LS_KEY       = 'mlp_projects';

  // Active editor tab index (0 = first/active tab)
  var activeEditorTabIdx = 0;

  // Update the three code cards from the given editor tab object
  function applyEditorTab(et) {
    var panels = [
      { lang: 'html', content: et.html || '' },
      { lang: 'css',  content: et.css  || '' },
      { lang: 'js',   content: et.js   || '' },
    ];
    panels.forEach(function(p, i) {
      var pre = document.getElementById('code-pre-' + i);
      if (pre) pre.textContent = p.content;
      var linesEl = pre && pre.closest('.code-card') && pre.closest('.code-card').querySelector('.cc-lines');
      if (linesEl) {
        var n = Math.max(1, (p.content.match(/\n/g) || []).length + 1);
        linesEl.textContent = n + ' line' + (n !== 1 ? 's' : '');
      }
    });
    // Sync TABS so buildSrcdoc uses the new content
    TABS[0].content = et.html || '';
    TABS[1].content = et.css  || '';
    TABS[2].content = et.js   || '';
  }

  function buildSrcdoc(){
    if(IS_SQL){
      var sqlCode=(TABS[0]&&TABS[0].content)||'';
      var sqlJson=JSON.stringify(sqlCode);
      return '<!DOCTYPE html><html><head><meta charset="utf-8">'
        +'<style>'
        +'*{box-sizing:border-box;margin:0;padding:0}'
        +'body{background:#0d1b2a;color:#cdd9e5;font-family:"JetBrains Mono","Fira Code",monospace;font-size:12.5px;line-height:1.7;height:100vh;display:flex;flex-direction:column;overflow:hidden}'
        +'#out{flex:1;overflow-y:auto;padding:12px 14px}'
        +'.ld{color:#8b949e;font-style:italic}'
        +'.stmt-label{color:#0ea5e9;font-weight:700;margin-top:10px;display:block}'
        +'.tbl-wrap{overflow-x:auto;margin:6px 0 10px}'
        +'table{border-collapse:collapse;font-size:11.5px;min-width:100%}'
        +'th{background:#1a2d3d;color:#7dd3fc;padding:4px 10px;text-align:left;border:1px solid #2a4a6a;white-space:nowrap}'
        +'td{padding:3px 10px;border:1px solid #1e3347;white-space:nowrap;vertical-align:top}'
        +'tr:nth-child(even) td{background:#0f1e2d}'
        +'.rows-count{color:#8b949e;font-size:11px;margin-bottom:6px}'
        +'.ok{color:#7ee787;white-space:pre-wrap}'
        +'.er{color:#f85149;white-space:pre-wrap}'
        +'</style>'
        +'</head><body>'
        +'<div id="out"><span class="ld">⚡ Loading SQLite runtime…</span></div>'
        +'<script>(function(){'
        +'var sql='+sqlJson+';'
        +'var out=document.getElementById("out");'
        +'function app(html){out.insertAdjacentHTML("beforeend",html);out.scrollTop=out.scrollHeight;}'
        +'var sc=document.createElement("script");'
        +'sc.src="https://cdnjs.cloudflare.com/ajax/libs/sql.js/1.12.0/sql-wasm.js";'
        +'sc.onload=function(){'
        +'out.innerHTML=\'<span class="ld">Initializing SQLite…</span>\';'
        +'initSqlJs({locateFile:function(f){return"https://cdnjs.cloudflare.com/ajax/libs/sql.js/1.12.0/"+f;}}).then(function(SQL){'
        +'out.innerHTML="";'
        +'var db=new SQL.Database();'
        +'var stmts=sql.split(";").map(function(s){return s.trim();}).filter(function(s){return s.length>0;});'
        +'stmts.forEach(function(stmt){'
        +'app("<span class=\'stmt-label\'>▶ "+stmt.substring(0,60).replace(/</g,"&lt;")+(stmt.length>60?"…":"")+"</span>");'
        +'try{'
        +'var res=db.exec(stmt);'
        +'if(res&&res.length>0){'
        +'res.forEach(function(r){'
        +'var cols=r.columns;var rows=r.values;'
        +'app("<div class=\'rows-count\'>"+rows.length+" row"+(rows.length!==1?"s":"")+"</div>");'
        +'var th=cols.map(function(c){return"<th>"+String(c).replace(/</g,"&lt;")+"</th>";}).join("");'
        +'var tbody=rows.map(function(row){return"<tr>"+row.map(function(v){return"<td>"+(v===null?"<span style=\'color:#8b949e;font-style:italic\'>NULL</span>":String(v).replace(/</g,"&lt;"))+"</td>";}).join("")+"</tr>";}).join("");'
        +'app("<div class=\'tbl-wrap\'><table><thead><tr>"+th+"</tr></thead><tbody>"+tbody+"</tbody></table></div>");'
        +'});'
        +'}else{'
        +'app("<span class=\'ok\'>✓ OK (no rows returned)</span><br>");'
        +'}'
        +'}catch(e){'
        +'app("<span class=\'er\'>✗ "+String(e.message||e).replace(/</g,"&lt;")+"</span><br>");'
        +'}'
        +'});'
        +'db.close();'
        +'}).catch(function(e){out.innerHTML=\'<span class="er">sql.js init error: \'+e.message+\'<\/span>\';});'
        +'};'
        +'sc.onerror=function(){out.innerHTML=\'<span class="er">Could not load sql.js. Check internet connection.<\/span>\';};'
        +'document.head.appendChild(sc);'
        +'})()<\/script>'
        +'</body></html>';
    }
    if(IS_PYTHON){
      var code=(TABS[0]&&TABS[0].content)||'';
      var codeJson=JSON.stringify(code);
      return '<!DOCTYPE html><html><head><meta charset="utf-8">'
        +'<style>'
        +'*{box-sizing:border-box;margin:0;padding:0}'
        +'body{background:#0d1117;color:#c9d1d9;font-family:"JetBrains Mono","Fira Code",monospace;font-size:12.5px;line-height:1.7;height:100vh;display:flex;flex-direction:column;overflow:hidden}'
        +'#out{flex:1;overflow-y:auto;padding:12px 14px;white-space:pre-wrap;word-break:break-word}'
        +'.ld{color:#8b949e;font-style:italic}'
        +'.ok{color:#7ee787}'
        +'.er{color:#f85149}'
        +'.wa{color:#f0883e}'
        +'</style>'
        +'</head><body>'
        +'<div id="out"><span class="ld">\uD83D\uDC0D Loading Python runtime\u2026</span></div>'
        +'<script>(function(){'
        +'var code='+codeJson+';'
        +'var out=document.getElementById("out");'
        +'function app(txt,cls){var s=document.createElement("span");s.className=cls;s.textContent=txt;out.appendChild(s);out.scrollTop=out.scrollHeight;}'
        +'var sc=document.createElement("script");'
        +'sc.src="https://cdn.jsdelivr.net/pyodide/v0.26.4/full/pyodide.js";'
        +'sc.onload=function(){'
        +'out.innerHTML=\'<span class="ld">Initializing\u2026</span>\';'
        +'window.loadPyodide().then(function(py){'
        +'out.innerHTML="";'
        +'try{py.runPython("import sys,io;sys.stdout=io.StringIO();sys.stderr=io.StringIO()");}catch(e){}'
        +'try{'
        +'py.runPython(code);'
        +'var so="",se="";'
        +'try{so=py.runPython("sys.stdout.getvalue()");}catch(e){}'
        +'try{se=py.runPython("sys.stderr.getvalue()");}catch(e){}'
        +'if(so)app(so,"ok");'
        +'if(se)app(se,"wa");'
        +'if(!so&&!se)app("(no output)","ld");'
        +'}catch(e){app(String(e.message||e),"er");}'
        +'}).catch(function(e){out.innerHTML=\'<span class="er">Pyodide init error: \'+e.message+\'<\/span>\';});'
        +'};'
        +'sc.onerror=function(){out.innerHTML=\'<span class="er">Could not load Pyodide. Check internet connection.<\/span>\';};'
        +'document.head.appendChild(sc);'
        +'})()<\/script>'
        +'</body></html>';
    }
    if(IS_RUST){
      // Rust: fetch is done from the parent page (runRust), not inside the iframe.
      // Return a static loading placeholder; runRust() will overwrite srcdoc with real output.
      return rustLoadingDoc();
    }
    if(IS_CSHARP){
      // C#: compiled from parent page via Wandbox (same pattern as Rust).
      // Return a loading placeholder; runCSharp() will overwrite with real output.
      return csLoadingDoc();
    }
    if(IS_LUA){
      var luaCode=(TABS[0]&&TABS[0].content)||'';
      var luaJson=JSON.stringify(luaCode);
      var fengariUrl=JSON.stringify('https://cdn.jsdelivr.net/npm/fengari-web@0.1.4/dist/fengari-web.js');
      return '<!DOCTYPE html><html><head><meta charset="utf-8">'
        +'<style>'
        +'*{box-sizing:border-box;margin:0;padding:0}'
        +'body{background:#0d1117;color:#c9d1d9;font-family:"JetBrains Mono","Fira Code",monospace;font-size:12.5px;line-height:1.7;height:100vh;display:flex;flex-direction:column;overflow:hidden}'
        +'#out{flex:1;overflow-y:auto;padding:12px 14px;white-space:pre-wrap;word-break:break-word}'
        +'.ld{color:#8b949e;font-style:italic}'
        +'.ok{color:#7ee787}'
        +'.er{color:#f85149}'
        +'</style>'
        +'</head><body>'
        +'<div id="out"><span class="ld">🌙 Loading Lua runtime…</span></div>'
        +'<script>(function(){'
        +'var code='+luaJson+';'
        +'var out=document.getElementById("out");'
        +'function app(txt,cls){var s=document.createElement("span");s.className=cls;s.textContent=txt;out.appendChild(s);out.scrollTop=out.scrollHeight;}'
        +'var sc=document.createElement("script");'
        +'sc.src='+fengariUrl+';'
        +'var savedDefine=(typeof window.define==="function"&&window.define.amd)?window.define:null;'
        +'if(savedDefine)window.define=undefined;'
        +'sc.onload=function(){'
        +'if(savedDefine)window.define=savedDefine;'
        +'var fg=window.fengari;'
        +'if(!fg){try{fg=fengari;}catch(e){}}'
        +'if(!fg||!fg.lua||!fg.lauxlib){out.innerHTML=\'<span class="er">Fengari runtime failed to load.<\/span>\';return;}'
        +'out.innerHTML="";'
        +'var L=fg.lauxlib.luaL_newstate();'
        +'fg.lualib.luaL_openlibs(L);'
        +'var lines=[];'
        +'fg.lua.lua_register(L,fg.to_luastring("print"),function(L2){'
        +'var n=fg.lua.lua_gettop(L2);var parts=[];'
        +'for(var i=1;i<=n;i++){try{fg.lauxlib.luaL_tolstring(L2,i,null);var s=fg.lua.lua_tojsstring(L2,-1);parts.push(s!==null&&s!==undefined?s:"");fg.lua.lua_pop(L2,1);}catch(e){parts.push("?");}}'
        +'lines.push(parts.join("\\t"));return 0;'
        +'});'
        +'fg.lua.lua_getglobal(L,fg.to_luastring("io"));'
        +'if(fg.lua.lua_istable(L,-1)){'
        +'fg.lua.lua_pushstring(L,fg.to_luastring("write"));'
        +'fg.lua.lua_pushcfunction(L,function(L2){var n=fg.lua.lua_gettop(L2);for(var i=1;i<=n;i++){var s=fg.lua.lua_tojsstring(L2,i);if(s)lines.push(s);}return 0;});'
        +'fg.lua.lua_settable(L,-3);}'
        +'fg.lua.lua_pop(L,1);'
        +'var ok=fg.lauxlib.luaL_dostring(L,fg.to_luastring(code));'
        +'var errMsg=ok!==fg.lua.LUA_OK?fg.lua.lua_tojsstring(L,-1)||"Runtime error":null;'
        +'fg.lua.lua_close(L);'
        +'var flat=[];lines.forEach(function(l){l.split("\\n").forEach(function(x){flat.push(x);});});'
        +'while(flat.length>0&&flat[flat.length-1]==="")flat.pop();'
        +'if(flat.length)app(flat.join("\\n"),"ok");'
        +'else if(!errMsg)app("(no output)","ld");'
        +'if(errMsg)app("\\n✗ "+errMsg,"er");'
        +'};'
        +'sc.onerror=function(){if(savedDefine)window.define=savedDefine;out.innerHTML=\'<span class="er">Could not load Fengari. Check internet connection.<\/span>\';};'
        +'document.head.appendChild(sc);'
        +'})()<\/script>'
        +'</body></html>';
    }
    if(IS_RUBY){
      var rubyCode=(TABS[0]&&TABS[0].content)||'';
      var rubyJson=JSON.stringify(rubyCode);
      return '<!DOCTYPE html><html><head><meta charset="utf-8">'
        +'<style>'
        +'*{box-sizing:border-box;margin:0;padding:0}'
        +'body{background:#1a0a0a;color:#fecaca;font-family:"JetBrains Mono","Fira Code",monospace;font-size:12.5px;line-height:1.7;height:100vh;display:flex;flex-direction:column;overflow:hidden}'
        +'#out{flex:1;overflow-y:auto;padding:12px 14px;white-space:pre-wrap;word-break:break-word}'
        +'.ld{color:#7f3030;font-style:italic}'
        +'.ok{color:#c9d1d9}'
        +'.er{color:#f85149}'
        +'.done{color:#34d399;font-size:11px}'
        +'</style>'
        +'</head><body>'
        +'<div id="out"><span class="ld">💎 Loading Ruby runtime\u2026</span></div>'
        +'<script>(function(){'
        +'var code='+rubyJson+';'
        +'var out=document.getElementById("out");'
        +'function app(txt,cls){var s=document.createElement("span");s.className=cls||"ok";s.textContent=txt;out.appendChild(s);out.scrollTop=out.scrollHeight;}'
        +'function loadScript(src,cb,err){var s=document.createElement("script");s.src=src;s.onload=cb;s.onerror=err;document.head.appendChild(s);}'
        +'window.onerror=function(msg,src,line){'
        +'out.innerHTML="";'
        +'app("\u2717 "+msg+(line?" (line "+line+")":""),"er");'
        +'return true;};'
        +'loadScript("https://cdn.opalrb.com/opal/1.8.2/opal.min.js",function(){'
        +'loadScript("https://cdn.opalrb.com/opal/1.8.2/opal-parser.min.js",function(){'
        +'out.innerHTML="";'
        +'var t0=Date.now();'
        +'try{'
        +'Opal.require("opal-parser");'
        /* Override Opal's $stdout.$write directly — reliable across all Opal 1.x versions */
        +'var captured=[];'
        +'var stdout=Opal.gvars["$stdout"];'
        +'var origWrite=stdout&&stdout["$write"];'
        +'if(stdout&&origWrite){'
        +'  stdout["$write"]=function(str){'
        +'    captured.push(String(str));'
        +'    return (str&&str.length)||0;'
        +'  };'
        +'}'
        /* Also capture console.log as a fallback for any Opal version */
        +'var origLog=console.log;'
        +'var logLines=[];'
        +'console.log=function(){logLines.push(Array.prototype.slice.call(arguments).join(" "));};'
        +'Opal.eval(code);'
        +'if(stdout&&origWrite)stdout["$write"]=origWrite;'
        +'console.log=origLog;'
        +'var ms=Date.now()-t0;'
        /* Prefer $stdout capture; fall back to console.log capture */
        +'var result=captured.length?captured.join(""):logLines.join("\\n");'
        +'result=result.replace(/\\n$/,"");'
        +'if(result){app(result,"ok");}'
        +'else{app("(no output)","ld");}'
        +'app("\\n\u2713 Done in "+ms+"ms","done");'
        +'}catch(e){'
        +'if(stdout&&origWrite)stdout["$write"]=origWrite;'
        +'console.log=origLog;'
        +'var msg=(e&&e.message)?e.message:String(e);'
        +'msg=msg.replace(/\\$opal/g,"").replace(/Opal\\./g,"");'
        +'app("\u2717 "+msg,"er");'
        +'}'
        +'},function(){out.innerHTML=\'<span class="er">Could not load Opal parser. Check internet connection.<\/span>\';});'
        +'},function(){out.innerHTML=\'<span class="er">Could not load Ruby runtime. Check internet connection.<\/span>\';});'
        +'})()<\/script>'
        +'</body></html>';
    }
    if(IS_DUCKDB){
      var ddbCode=(TABS[0]&&TABS[0].content)||'';
      var ddbJson=JSON.stringify(ddbCode);
      return '<!DOCTYPE html><html><head><meta charset="utf-8">'
        +'<style>'
        +'*{box-sizing:border-box;margin:0;padding:0}'
        +'body{background:#0f172a;color:#e2e8f0;font-family:"JetBrains Mono","Fira Code",monospace;font-size:12.5px;line-height:1.6;height:100vh;display:flex;flex-direction:column;overflow:hidden}'
        +'#ddb-toolbar{display:flex;align-items:center;gap:8px;padding:8px 12px;background:#1e293b;border-bottom:1px solid #334155;flex-shrink:0}'
        +'#ddb-run{background:#FFBC00;color:#0f172a;border:none;border-radius:5px;padding:4px 14px;font-size:12px;font-weight:700;cursor:pointer;font-family:inherit}'
        +'#ddb-run:hover{background:#f5c842}'
        +'#ddb-status{font-size:11px;color:#94a3b8;margin-left:auto}'
        +'#ddb-out{flex:1;overflow-y:auto;padding:12px 14px}'
        +'.ddb-empty{color:#64748b;font-style:italic}'
        +'.ddb-err{color:#ef4444;white-space:pre-wrap;word-break:break-all}'
        +'.ddb-msg{color:#94a3b8;font-style:italic}'
        +'.ddb-tbl-wrap{overflow-x:auto;margin-top:4px}'
        +'.ddb-tbl{border-collapse:collapse;font-size:12px;min-width:100%}'
        +'.ddb-tbl th{background:#1e293b;color:#FFBC00;padding:5px 10px;text-align:left;border-bottom:1px solid #334155;white-space:nowrap}'
        +'.ddb-tbl td{padding:4px 10px;border-bottom:1px solid #1e293b;color:#e2e8f0;white-space:nowrap}'
        +'.ddb-tbl tr:nth-child(even) td{background:rgba(255,255,255,0.03)}'
        +'.ddb-count{font-size:11px;color:#64748b;margin-top:6px}'
        +'</style>'
        +'</head><body>'
        +'<div id="ddb-toolbar">'
        +'<svg viewBox="0 0 24 24" width="16" height="16" fill="none"><path d="M12 2C6.477 2 2 6.477 2 12s4.477 10 10 10 10-4.477 10-10S17.523 2 12 2z" fill="#FFBC00"/><path d="M8 8h8v2H8V8zM8 11h8v2H8v-2zM8 14h5v2H8v-2z" fill="#0f172a"/></svg>'
        +'<strong style="color:#FFBC00;font-size:12px;">DuckDB</strong>'
        +'<button id="ddb-run">&#9654; Run</button>'
        +'<span id="ddb-status">Loading DuckDB WASM…</span>'
        +'</div>'
        +'<div id="ddb-out"><span class="ddb-msg">Initialising DuckDB WASM…</span></div>'
        +'<script>(function(){'
        +'var sql='+ddbJson+';'
        +'var out=document.getElementById("ddb-out");'
        +'var status=document.getElementById("ddb-status");'
        +'var runBtn=document.getElementById("ddb-run");'
        +'var db=null,conn=null;'
        +'function setStatus(s){if(status)status.textContent=s;}'
        +'function showErr(msg){out.innerHTML=\'<span class="ddb-err">\'+msg.replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;")+"<\/span>";}'
        +'function renderResult(res){'
        +'if(!res||!res.schema||res.schema.fields.length===0){out.innerHTML=\'<span class="ddb-msg">Query executed (no rows returned).<\/span>\';return;}'
        +'var cols=res.schema.fields.map(function(f){return f.name;});'
        +'var rows=res.toArray();'
        +'var h=\'<div class="ddb-tbl-wrap"><table class="ddb-tbl"><thead><tr>\';'
        +'cols.forEach(function(c){h+=\'<th>\'+c.replace(/&/g,"&amp;").replace(/</g,"&lt;")+"<\/th>";});'
        +'h+="<\/tr><\/thead><tbody>";'
        +'rows.forEach(function(row){'
        +'h+="<tr>";'
        +'cols.forEach(function(c){var v=row[c];h+=\'<td>\'+(v===null||v===undefined?"<em style=\'color:#64748b\'>NULL<\/em>":String(v).replace(/&/g,"&amp;").replace(/</g,"&lt;"))+"<\/td>";});'
        +'h+="<\/tr>";'
        +'});'
        +'h+="<\/tbody><\/table><\/div>";'
        +'h+=\'<div class="ddb-count">\'+rows.length+" row"+(rows.length!==1?"s":"")+" returned<\/div>";'
        +'out.innerHTML=h;'
        +'}'
        +'async function runQuery(){'
        +'if(!conn){showErr("DuckDB not ready.");return;}'
        +'var q=sql.trim();if(!q){out.innerHTML=\'<span class="ddb-empty">-- no query --<\/span>\';return;}'
        +'setStatus("Running…");runBtn.disabled=true;'
        +'try{'
        +'var stmts=q.split(/;\\s*(?=(?:[^\']*\'[^\']*\')*[^\']*$)/).map(function(s){return s.trim();}).filter(Boolean);'
        +'var lastRes=null;'
        +'for(var i=0;i<stmts.length;i++){var r=await conn.query(stmts[i]);lastRes=r;}'
        +'renderResult(lastRes);'
        +'setStatus("Done");'
        +'}catch(e){showErr(String(e.message||e));setStatus("Error");}'
        +'runBtn.disabled=false;'
        +'}'
        +'runBtn.addEventListener("click",runQuery);'
        +'(async function init(){'
        +'try{'
        +'var CDN="https://cdn.jsdelivr.net/npm/@duckdb/duckdb-wasm@1.28.0/dist/";'
        +'var sc=document.createElement("script");'
        +'sc.src=CDN+"duckdb-browser-eh.worker.js";sc.type="module";'
        +'var bundle={mainModule:CDN+"duckdb-eh.wasm",mainWorker:CDN+"duckdb-browser-eh.worker.js"};'
        +'var ddbSc=document.createElement("script");'
        +'ddbSc.src=CDN+"duckdb-browser-eh.js";'
        +'document.head.appendChild(ddbSc);'
        +'ddbSc.onload=async function(){'
        +'try{'
        +'var duckdb=window.duckdb;'
        +'if(!duckdb){throw new Error("DuckDB bundle failed to load");}'
        +'var logger=new duckdb.ConsoleLogger();'
        +'var worker=await duckdb.createWorker(bundle.mainWorker);'
        +'db=new duckdb.AsyncDuckDB(logger,worker);'
        +'await db.instantiate(bundle.mainModule);'
        +'conn=await db.connect();'
        +'setStatus("Ready");'
        +'out.innerHTML=\'<span class="ddb-msg">DuckDB ready. Click Run to execute.<\/span>\';'
        +'await runQuery();'
        +'}catch(e){showErr("Init error: "+String(e.message||e));setStatus("Error");}'
        +'};'
        +'ddbSc.onerror=function(){showErr("Could not load DuckDB WASM. Check internet connection.");setStatus("Error");};'
        +'}catch(e){showErr("Init error: "+String(e.message||e));setStatus("Error");}'
        +'})();'
        +'})()<\/script>'
        +'</body></html>';
    }
    var html=TABS[0].content||'',css=TABS[1].content||'',js=TABS[2].content||'';
    var doc=html||'<!DOCTYPE html><html><head></head><body></body></html>';
    if(css){doc=doc.indexOf('</head>')!==-1?doc.replace('</head>','<style>'+css+'</style></head>'):'<style>'+css+'</style>'+doc;}
    if(js){doc=doc.indexOf('</body>')!==-1?doc.replace('</body>','<script>'+js+'<\/script></body>'):doc+'<script>'+js+'<\/script>';}
    return doc;
  }

  // ── C# shared styles + helpers (Wandbox, same pattern as Rust) ──────────
  var CS_CSS = '*{box-sizing:border-box;margin:0;padding:0}'
    +'body{background:#0e0e0e;color:#d4d4d4;font-family:"JetBrains Mono","Fira Code",monospace;font-size:12.5px;line-height:1.7;height:100vh;display:flex;flex-direction:column;overflow:hidden}'
    +'#out{flex:1;overflow-y:auto;padding:12px 14px;white-space:pre-wrap;word-break:break-word}'
    +'.ld{color:#6b7280;font-style:italic}.ok{color:#34d399}.er{color:#f87171}.ts{color:#a78bfa;font-weight:700}';

  function csLoadingDoc() {
    return '<!DOCTYPE html><html><head><meta charset="utf-8"><style>'+CS_CSS+'</style></head>'
      +'<body><div id="out"><span class="ld">\u23F3 Compiling via Wandbox\u2026</span></div></body></html>';
  }

  function csResultDoc(stdout, stderr, compErr, exitCode, ms) {
    function esc(s){ return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }
    var lines = '<span class="ts">&#9654; Run &mdash; '+new Date().toLocaleTimeString()+'</span>\n';
    if(compErr && compErr.trim()) lines += '<span class="er">'+esc(compErr.trimEnd())+'</span>\n';
    if(stdout && stdout.trim()) lines += esc(stdout.trimEnd())+'\n';
    if(stderr && stderr.trim()) lines += '<span class="er">'+esc(stderr.trimEnd())+'</span>\n';
    var ok = (String(exitCode) === '0') && !(compErr && compErr.trim());
    if(ok){
      if(!stdout && !stderr && !compErr) lines += '<span class="ld">(no output)</span>\n';
      lines += '<span class="ok">&#10003; Compiled and ran in '+ms+'ms</span>';
    } else {
      if(!stdout && !stderr && !compErr) lines += '<span class="er">Build failed</span>\n';
      lines += '<span class="er">&#10007; Build failed ('+ms+'ms)</span>';
    }
    return '<!DOCTYPE html><html><head><meta charset="utf-8"><style>'+CS_CSS+'</style></head>'
      +'<body><div id="out">'+lines+'</div></body></html>';
  }

  var _csRetries = 0;
  function runCSharp(iframe) {
    iframe.srcdoc = csLoadingDoc();
    var code = (TABS[0] && TABS[0].content) || '';
    var t0 = Date.now();
    function attempt() {
      fetch('https://wandbox.org/api/compile.json', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ compiler: 'mono-6.12.0.199', code: code, stdin: '', 'compiler-option-raw': '', 'runtime-option-raw': '' })
      })
      .then(function(r){ return r.json(); })
      .then(function(d){
        _csRetries = 0;
        var ms = Date.now() - t0;
        iframe.srcdoc = csResultDoc(d.program_output||'', d.program_error||'', d.compiler_error||'', d.status||'', ms);
      })
      .catch(function(e){
        if (_csRetries < 2) {
          _csRetries++;
          setTimeout(attempt, 1800);
          return;
        }
        _csRetries = 0;
        var msg = 'Network error \u2014 could not reach Wandbox\n'+(e&&e.message?e.message:String(e));
        iframe.srcdoc = csResultDoc('', msg, '', '1', Date.now()-t0);
      });
    }
    attempt();
  }

  // Rust shared styles used by both loading placeholder and result page
  var RUST_CSS = '*{box-sizing:border-box;margin:0;padding:0}'
    +'body{background:#0f0a05;color:#f0e8e0;font-family:"JetBrains Mono","Fira Code",monospace;font-size:12.5px;line-height:1.7;height:100vh;display:flex;flex-direction:column;overflow:hidden}'
    +'#out{flex:1;overflow-y:auto;padding:12px 14px;white-space:pre-wrap;word-break:break-word}'
    +'.ld{color:#8a6e58;font-style:italic}.ok{color:#3dba6b}.er{color:#f87171}.ts{color:#e8632a;font-weight:700}';

  function rustLoadingDoc() {
    return '<!DOCTYPE html><html><head><meta charset="utf-8"><style>'+RUST_CSS+'</style></head>'
      +'<body><div id="out"><span class="ld">\u23F3 Compiling via Rust Playground\u2026</span></div></body></html>';
  }

  function rustResultDoc(stdout, stderr, hasError, ms, channel) {
    var lines = '';
    function esc(s){ return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }
    lines += '<span class="ts">&#9654; Run ['+esc(channel)+'] &mdash; '+new Date().toLocaleTimeString()+'</span>\n';
    if(stdout && stdout.trim()) lines += esc(stdout.trimEnd())+'\n';
    if(stderr && stderr.trim()) lines += '<span class="er">'+esc(stderr.trimEnd())+'</span>\n';
    if(!hasError){
      if(!stdout && !stderr) lines += '<span class="ld">(no output)</span>\n';
      lines += '<span class="ok">&#10003; Compiled and ran in '+ms+'ms</span>';
    } else {
      if(!stdout && !stderr) lines += '<span class="er">Build failed</span>\n';
      lines += '<span class="er">&#10007; Build failed ('+ms+'ms)</span>';
    }
    return '<!DOCTYPE html><html><head><meta charset="utf-8"><style>'+RUST_CSS+'</style></head>'
      +'<body><div id="out">'+lines+'</div></body></html>';
  }

  // Run Rust from the PARENT page (not inside the sandbox) to avoid CORS blocks.
  function runRust(iframe) {
    iframe.srcdoc = rustLoadingDoc();
    var code = (TABS[0] && TABS[0].content) || '';
    var channel = RUST_CHANNEL || 'stable';
    var t0 = Date.now();
    fetch('https://play.rust-lang.org/execute', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ channel: channel, mode: 'debug', edition: '2021', code: code, crateType: 'bin', tests: false })
    })
    .then(function(r){ return r.json(); })
    .then(function(d){
      var ms = Date.now() - t0;
      iframe.srcdoc = rustResultDoc(d.stdout||'', d.stderr||'', !!d.error, ms, channel);
    })
    .catch(function(e){
      var msg = 'Network error \u2014 could not reach play.rust-lang.org\n'+(e&&e.message?e.message:String(e));
      iframe.srcdoc = rustResultDoc('', msg, true, Date.now()-t0, channel);
    });
  }

  // ── PHP: render saved output ──────────────────────────────────────────
  var PHP_CSS = '*{box-sizing:border-box;margin:0;padding:0}'
    +'body{background:#0e0e0e;color:#d4d4d4;font-family:"JetBrains Mono","Fira Code",monospace;font-size:12.5px;line-height:1.7;height:100vh;display:flex;flex-direction:column;overflow:hidden}'
    +'#out{flex:1;overflow-y:auto;padding:12px 14px;white-space:pre-wrap;word-break:break-word}'
    +'.ts{color:#7c3aed;font-weight:700}'
    +'.empty{color:#555;font-style:italic}';

  function phpOutputDoc(output, isHtml, outAt) {
    if(!output || output === '') {
      return '<!DOCTYPE html><html><head><meta charset="utf-8"><style>'+PHP_CSS+'</style></head>'
        +'<body><div id="out"><span class="empty">No output saved yet.\nThe author has not run this project.</span></div></body></html>';
    }
    if(isHtml) {
      return output;
    }
    function esc(s){return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');}
    var ts = outAt ? '<span class="ts">&#9654; PHP output</span>\n' : '';
    return '<!DOCTYPE html><html><head><meta charset="utf-8"><style>'+PHP_CSS+'</style></head>'
      +'<body><div id="out">'+ts+esc(output)+'</div></body></html>';
  }

  function loadPhpOutput(iframe) {
    iframe.srcdoc = phpOutputDoc(PHP_OUTPUT, PHP_OUT_IS_HTML, PHP_OUT_AT);
  }

  function loadPreview(iframe){
    if(IS_RUST){ runRust(iframe); return; }
    if(IS_CSHARP){ runCSharp(iframe); return; }
    if(IS_PHP){ loadPhpOutput(iframe); return; }
    iframe.srcdoc=buildSrcdoc();
  }

  // Editor tab bar switching (not used for Python/C#/PHP projects)
  var tabBar = document.getElementById('mlp-editor-tab-bar');
  if (!IS_PYTHON && !IS_SQL && !IS_LUA && !IS_DUCKDB && !IS_RUBY && !IS_RUST && !IS_CSHARP && !IS_PHP && tabBar) {
    tabBar.addEventListener('click', function(e) {
      var btn = e.target.closest('.editor-tab-btn');
      if (!btn) return;
      var idx = parseInt(btn.getAttribute('data-etab'), 10);
      if (isNaN(idx) || idx === activeEditorTabIdx) return;
      activeEditorTabIdx = idx;
      tabBar.querySelectorAll('.editor-tab-btn').forEach(function(b) {
        b.classList.toggle('active', b === btn);
      });
      applyEditorTab(EDITOR_TABS[idx]);
      var pf2 = document.getElementById('mlp-preview-iframe');
      if (pf2) loadPreview(pf2);
    });
  }

  // Auto-load preview on page ready (Python: runs via Pyodide in srcdoc; HTML: normal srcdoc)
  var pf=document.getElementById('mlp-preview-iframe');
  if(pf) loadPreview(pf);
  var refreshBtn=document.getElementById('mlp-refresh-btn');
  if(refreshBtn) refreshBtn.addEventListener('click',function(){loadPreview(pf);});

  // Fullscreen
  var fso=document.getElementById('mlp-fs-overlay');
  var fsi=document.getElementById('mlp-fs-iframe');
  var fsBtn=document.getElementById('mlp-fs-btn');
  var fsClose=document.getElementById('mlp-fs-close');
  if(fsBtn)fsBtn.addEventListener('click',function(){loadPreview(fsi);fso.classList.add('active');});
  if(fsClose)fsClose.addEventListener('click',function(){fso.classList.remove('active');if(fsi)fsi.srcdoc='';});

  // Toast helper
  var toastEl=document.getElementById('mlp-toast');
  var toastMsg=document.getElementById('mlp-toast-msg');
  function showToast(msg){toastMsg.textContent=msg;toastEl.classList.add('show');setTimeout(function(){toastEl.classList.remove('show');},3200);}

  // Copy buttons — one per code card
  document.querySelectorAll('.cc-copy').forEach(function(btn){
    btn.addEventListener('click',function(){
      var idx=btn.getAttribute('data-card');
      var pre=document.getElementById('code-pre-'+idx);
      if(!pre) return;
      var text=pre.textContent||pre.innerText||'';
      if(navigator.clipboard&&navigator.clipboard.writeText){
        navigator.clipboard.writeText(text).then(function(){
          markCopied(btn);
        }).catch(function(){fallbackCopy(btn,text);});
      } else { fallbackCopy(btn,text); }
    });
  });
  function markCopied(btn){
    btn.classList.add('copied');
    btn.innerHTML='<i class="fas fa-check"></i> Copied!';
    setTimeout(function(){
      btn.classList.remove('copied');
      btn.innerHTML='<i class="fas fa-copy"></i> Copy';
    },2000);
  }
  function fallbackCopy(btn,text){
    var ta=document.createElement('textarea');
    ta.value=text;ta.style.position='fixed';ta.style.opacity='0';
    document.body.appendChild(ta);ta.select();
    try{document.execCommand('copy');markCopied(btn);}catch(e){}
    document.body.removeChild(ta);
  }

  // Add to My Projects — saves the full published payload into mlp_projects localStorage
  document.getElementById('mlp-fork-btn').addEventListener('click',function(){
    try{
      var projects=[];
      try{var r=localStorage.getItem(LS_KEY);if(r){var p=JSON.parse(r);if(Array.isArray(p))projects=p;}}catch(e){}
      var parsed=typeof PAYLOAD_RAW==='string'?JSON.parse(PAYLOAD_RAW):PAYLOAD_RAW;
      var newProj=Object.assign({},parsed,{
        id:'fork_'+TOKEN+'_'+Date.now(),
        name:PROJ_NAME+' (fork)',
        forkedFrom:TOKEN,
        isPrivate:true,
        createdAt:new Date().toISOString(),
        updatedAt:new Date().toISOString()
      });
      projects.push(newProj);
      localStorage.setItem(LS_KEY,JSON.stringify(projects));
      showToast('Added "'+PROJ_NAME+'" to your projects!');
    }catch(e){showToast('Could not save — localStorage may be full.');}
  });

  // ── Like / Dislike reactions ──
  (function(){
    var AJAX_URL   = <?php echo $js_ajax_url_p1; ?>;
    var NONCE      = <?php echo $js_share_nonce_p1; ?>;
    var likeBtn    = document.getElementById('mlp-like-btn');
    var dislikeBtn = document.getElementById('mlp-dislike-btn');
    if (!likeBtn || !dislikeBtn) return;
    if (<?php echo $js_viewer_liked_p1; ?>) likeBtn.classList.add('sb-react-on');
    if (<?php echo $js_viewer_made_p1; ?>)  dislikeBtn.classList.add('sb-react-on');
    function sendReaction(kind, state){
      if (!window.fetch || !AJAX_URL || !TOKEN) return;
      var fd = new FormData();
      fd.append('action',   'mlp_react_to_share');
      fd.append('nonce',    NONCE);
      fd.append('token',    TOKEN);
      fd.append('reaction', kind === 'dislike' ? 'made' : 'like');
      fd.append('state',    state ? '1' : '0');
      fetch(AJAX_URL, {method:'POST',body:fd,credentials:'same-origin'}).catch(function(){});
    }
    [likeBtn, dislikeBtn].forEach(function(btn){
      btn.addEventListener('click', function(){
        var kind  = btn.getAttribute('data-kind');
        var isOn  = btn.classList.contains('sb-react-on');
        var other = kind === 'like' ? dislikeBtn : likeBtn;
        if (other.classList.contains('sb-react-on')) {
          other.classList.remove('sb-react-on');
          sendReaction(kind === 'like' ? 'dislike' : 'like', false);
          var otherStat = document.getElementById(kind === 'like' ? 'mlp-stat-dislikes' : 'mlp-stat-likes');
          if(otherStat){ otherStat.textContent = Math.max(0, parseInt(otherStat.textContent,10)-1); }
        }
        if (isOn) {
          btn.classList.remove('sb-react-on');
          sendReaction(kind, false);
          var st = document.getElementById(kind === 'like' ? 'mlp-stat-likes' : 'mlp-stat-dislikes');
          if(st){ st.textContent = Math.max(0, parseInt(st.textContent,10)-1); }
        } else {
          btn.classList.add('sb-react-on');
          sendReaction(kind, true);
          var st2 = document.getElementById(kind === 'like' ? 'mlp-stat-likes' : 'mlp-stat-dislikes');
          if(st2){ st2.textContent = parseInt(st2.textContent,10)+1; }
        }
      });
    });
  })();

  // ── Comments ──
  (function(){
    var AJAX_URL = <?php echo $js_ajax_url_p1; ?>;
    var CNONCE   = <?php echo $js_comment_nonce_p1; ?>;
    var PUB_TOK  = <?php echo $js_pub_token_p1; ?>;
    var PUB_NAME = <?php echo $js_pub_name_p1; ?>;
    var ID       = TOKEN;
    var LS_NAME  = 'mlp_commenter_name';
    var LS_CID   = 'mlp_commenter_id';
    var RL_KEY   = 'mlp_cmt_last_' + ID;

    var cmtId = '';
    try { cmtId = localStorage.getItem(LS_CID) || ''; } catch(e){}
    if (!cmtId) {
      cmtId = 'c' + Math.random().toString(36).slice(2,16) + Date.now().toString(36);
      try { localStorage.setItem(LS_CID, cmtId); } catch(e){}
    }

    var isPub = false;
    try {
      var _pp = JSON.parse(localStorage.getItem('mlp_projects')||'[]');
      isPub = Array.isArray(_pp) && _pp.some(function(p){ return p.shareToken === ID; });
    } catch(e){}

    var storedName = '';
    try { storedName = localStorage.getItem(LS_NAME) || ''; } catch(e){}

    var nameInput      = document.getElementById('mlp-comment-name');
    var submitBtn      = document.getElementById('mlp-comment-submit');
    var nameOverlay    = document.getElementById('mlp-name-overlay');
    var nameModal      = document.getElementById('mlp-name-input');
    var nameConfirmBtn = document.getElementById('mlp-name-confirm');
    var nameErrEl      = document.getElementById('mlp-name-err');
    var errEl          = document.getElementById('mlp-comment-err');
    var _editMode = false; var _editIdx = -1; var _sortedCache = []; var _pendingPost = null;

    function showErr(m){ if(errEl){errEl.textContent=m;errEl.style.display=m?'block':'none';} }
    function showNameErr(m){ if(nameErrEl){nameErrEl.textContent=m;nameErrEl.style.display=m?'block':'none';} }
    function updatePostBtn(){
      if (!submitBtn || _editMode) return;
      var ok = isPub || !!storedName;
      submitBtn.disabled = !ok; submitBtn.style.opacity = ok ? '' : '0.5';
      submitBtn.title = ok ? '' : 'Set a username first';
    }

    if (isPub) {
      if (nameInput) { nameInput.value = PUB_NAME || storedName || 'Publisher'; nameInput.readOnly = true; nameInput.style.opacity='0.65'; nameInput.style.cursor='not-allowed'; nameInput.title='Publisher name — cannot be changed'; }
      if (submitBtn) { submitBtn.disabled = false; submitBtn.style.opacity = ''; }
    } else {
      if (storedName && nameInput) { nameInput.value = storedName; nameInput.readOnly = true; nameInput.style.opacity='0.65'; nameInput.style.cursor='not-allowed'; nameInput.title='Username is permanent'; }
      updatePostBtn();
    }

    if (nameConfirmBtn) nameConfirmBtn.addEventListener('click', function(){
      var n = (nameModal ? nameModal.value : '').trim();
      if (!n) { showNameErr('Please enter a username.'); return; }
      if (n.length < 2) { showNameErr('At least 2 characters required.'); return; }
      storedName = n;
      try { localStorage.setItem(LS_NAME, n); } catch(e){}
      if (nameInput) { nameInput.value = n; nameInput.readOnly = true; nameInput.style.opacity='0.65'; nameInput.style.cursor='not-allowed'; nameInput.title='Username is permanent'; }
      if (nameOverlay) nameOverlay.classList.remove('active');
      showNameErr(''); updatePostBtn();
      if (typeof _pendingPost === 'function') { _pendingPost(); _pendingPost = null; }
    });
    if (nameModal) nameModal.addEventListener('keydown', function(e){ if (e.key==='Enter'&&nameConfirmBtn) nameConfirmBtn.click(); });

    var writeToggle = document.getElementById('mlp-write-toggle');
    var commentForm = document.getElementById('mlp-comment-form');
    if (writeToggle && commentForm) {
      writeToggle.addEventListener('click', function(){
        if (_editMode) { cancelEdit(); return; }
        if (!isPub && !storedName) {
          if (nameOverlay) { if (nameModal) nameModal.value=''; nameOverlay.classList.add('active'); if (nameModal) nameModal.focus(); }
          return;
        }
        var open = commentForm.style.display !== 'none';
        commentForm.style.display = open ? 'none' : 'block';
        writeToggle.innerHTML = open ? '<i class="fas fa-plus" style="font-size:.6rem"></i> Write' : '<i class="fas fa-times" style="font-size:.6rem"></i> Close';
      });
    }

    function esc(s){ return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }
    function timeAgo(ts){ var d=Math.floor(Date.now()/1000)-ts; if(d<60) return d+'s ago'; if(d<3600) return Math.floor(d/60)+'m ago'; if(d<86400) return Math.floor(d/3600)+'h ago'; return Math.floor(d/86400)+'d ago'; }
    function sortComments(arr){
      var pinned=[],pubC=[],rest=[];
      arr.forEach(function(c,i){ c._i=i; });
      arr.forEach(function(c){ if(c.is_pinned) pinned.push(c); else if(c.is_publisher) pubC.push(c); else rest.push(c); });
      return pinned.concat(pubC,rest.slice().reverse());
    }

    function render(comments){
      _sortedCache=[];
      var list=document.getElementById('mlp-comments-list'), countEl=document.getElementById('mlp-comments-count');
      var cnt=comments?comments.length:0;
      if(countEl) countEl.innerHTML='<i class="fas fa-comments" style="font-size:.65rem"></i> '+cnt+' Comment'+(cnt===1?'':'s');
      if(!list) return;
      if(!comments||!cnt){ list.innerHTML='<div class="sb-comment-empty">No comments yet. Be the first!</div>'; return; }
      var sorted=sortComments(comments.slice()); _sortedCache=sorted; var html='';
      sorted.forEach(function(c){
        var cls='sb-comment-item';
        if(c.is_publisher) cls+=' sb-comment-publisher';
        if(c.is_pinned) cls+=' sb-comment-pinned';
        var pinBtn=isPub?'<button class="sb-pin-btn'+(c.is_pinned?' pinned':'')+'" data-idx="'+c._i+'" title="'+(c.is_pinned?'Unpin':'Pin to top')+'">📌</button>':'';
        var pinBadge=c.is_pinned?'<span class="sb-pin-badge" title="Pinned">📌</span>':'';
        var pubBadge=c.is_publisher?'<span class="sb-comment-pub-badge">Publisher</span>':'';
        var editedTag=c.edited?' <span style="font-size:.58rem;color:var(--muted2)">(edited)</span>':'';
        var actions='';
        if(c.is_own||isPub){
          actions+='<button class="sb-cmt-act" data-action="edit" data-idx="'+c._i+'" title="Edit">✏️</button>';
          actions+='<button class="sb-cmt-act" data-action="delete" data-idx="'+c._i+'" title="Delete">🗑️</button>';
        }
        html+='<div class="'+cls+'">'
          +'<div style="display:flex;align-items:center;justify-content:space-between;gap:4px">'
          +'<div class="sb-comment-author'+(c.is_publisher?' sb-comment-pub-author':'')+'">'+esc(c.name)+pubBadge+pinBadge+'</div>'
          +'<div style="display:flex;gap:2px;flex-shrink:0">'+pinBtn+actions+'</div>'
          +'</div>'
          +'<div class="sb-comment-text">'+esc(c.text)+editedTag+'</div>'
          +'<div class="sb-comment-time">'+timeAgo(c.time)+'</div>'
          +'</div>';
      });
      list.innerHTML=html;
      list.querySelectorAll('.sb-pin-btn').forEach(function(btn){ btn.addEventListener('click',function(){ pinComment(parseInt(btn.getAttribute('data-idx'),10)); }); });
      list.querySelectorAll('.sb-cmt-act').forEach(function(btn){
        btn.addEventListener('click',function(){
          var action=btn.getAttribute('data-action'), idx=parseInt(btn.getAttribute('data-idx'),10);
          if(action==='delete') deleteComment(idx); else if(action==='edit') startEdit(idx);
        });
      });
      list.scrollTop=list.scrollHeight;
    }

    function load(){
      if(!AJAX_URL||!ID) return;
      fetch(AJAX_URL+'?action=mlp_get_comments&id='+encodeURIComponent(ID)+'&cmt_id='+encodeURIComponent(cmtId),{credentials:'same-origin'})
        .then(function(r){return r.json();}).then(function(d){if(d.success) render(d.data.comments);}).catch(function(){});
    }
    function pinComment(idx){
      if(!AJAX_URL||!ID||!PUB_TOK) return;
      var fd=new FormData(); fd.append('action','mlp_pin_comment'); fd.append('nonce',CNONCE); fd.append('id',ID); fd.append('index',idx); fd.append('pub_token',PUB_TOK);
      fetch(AJAX_URL,{method:'POST',body:fd,credentials:'same-origin'}).then(function(r){return r.json();}).then(function(d){if(d.success) load();}).catch(function(){});
    }
    function deleteComment(idx){
      if(!AJAX_URL||!ID) return;
      if(!confirm('Delete this comment?')) return;
      var fd=new FormData(); fd.append('action','mlp_delete_comment'); fd.append('nonce',CNONCE); fd.append('id',ID); fd.append('index',idx);
      if(isPub) fd.append('pub_token',PUB_TOK); else fd.append('cmt_id',cmtId);
      fetch(AJAX_URL,{method:'POST',body:fd,credentials:'same-origin'})
        .then(function(r){return r.json();}).then(function(d){ if(d.success) load(); else showErr((d.data&&d.data.message)||'Could not delete.'); }).catch(function(){});
    }
    function startEdit(idx){
      var c=_sortedCache.find(function(x){ return x._i===idx; }); if(!c) return;
      var textEl=document.getElementById('mlp-comment-text'); if(!textEl) return;
      _editMode=true; _editIdx=idx; textEl.value=c.text;
      if(commentForm) commentForm.style.display='block';
      if(writeToggle) writeToggle.innerHTML='<i class="fas fa-times" style="font-size:.6rem"></i> Close';
      if(submitBtn){ submitBtn.disabled=false; submitBtn.innerHTML='<i class="fas fa-save" style="font-size:.7rem"></i> Save Edit'; }
      showErr('Editing — click Close to cancel.');
    }
    function cancelEdit(){
      _editMode=false; _editIdx=-1;
      var textEl=document.getElementById('mlp-comment-text'); if(textEl) textEl.value='';
      if(submitBtn) submitBtn.innerHTML='<i class="fas fa-paper-plane" style="font-size:.7rem"></i> Post';
      if(commentForm) commentForm.style.display='none';
      if(writeToggle) writeToggle.innerHTML='<i class="fas fa-plus" style="font-size:.6rem"></i> Write';
      showErr(''); updatePostBtn();
    }
    function doPost(){
      var name=isPub?(PUB_NAME||storedName||'Publisher'):storedName;
      var text=(document.getElementById('mlp-comment-text')||{}).value||'';
      if(!text.trim()){ showErr('Please write something first.'); return; }
      if(!name){ showErr('Please set a username first.'); return; }
      if(!_editMode){
        var lastPost=0; try{ lastPost=parseInt(localStorage.getItem(RL_KEY)||'0',10)||0; }catch(e){}
        if(lastPost&&(Date.now()-lastPost)<600000){ var wait=Math.ceil((600000-(Date.now()-lastPost))/60000); showErr('Please wait '+wait+' more minute'+(wait===1?'':'s')+' before posting again.'); return; }
      }
      submitBtn.disabled=true; submitBtn.innerHTML='<i class="fas fa-spinner fa-spin" style="font-size:.7rem"></i> '+(_editMode?'Saving...':'Posting...');
      if(_editMode){
        var fd=new FormData(); fd.append('action','mlp_edit_comment'); fd.append('nonce',CNONCE); fd.append('id',ID); fd.append('index',_editIdx); fd.append('text',text);
        if(isPub) fd.append('pub_token',PUB_TOK); else fd.append('cmt_id',cmtId);
        fetch(AJAX_URL,{method:'POST',body:fd,credentials:'same-origin'})
          .then(function(r){return r.json();}).then(function(d){
            if(d.success){ cancelEdit(); load(); }
            else{ showErr((d.data&&d.data.message)||'Could not save.'); submitBtn.disabled=false; submitBtn.innerHTML='<i class="fas fa-save" style="font-size:.7rem"></i> Save Edit'; }
          }).catch(function(){ showErr('Network error.'); submitBtn.disabled=false; submitBtn.innerHTML='<i class="fas fa-save" style="font-size:.7rem"></i> Save Edit'; });
        return;
      }
      var fd=new FormData(); fd.append('action','mlp_post_comment'); fd.append('nonce',CNONCE);
      fd.append('id',ID); fd.append('name',name); fd.append('text',text); fd.append('cmt_id',cmtId);
      if(isPub) fd.append('pub_token',PUB_TOK);
      fetch(AJAX_URL,{method:'POST',body:fd,credentials:'same-origin'})
        .then(function(r){return r.json();}).then(function(d){
          if(d.success){ document.getElementById('mlp-comment-text').value=''; showErr(''); try{ localStorage.setItem(RL_KEY,String(Date.now())); }catch(e){} load(); }
          else{
            var msg=(d.data&&d.data.message)||'Could not post comment.';
            showErr(msg);
            if(msg.indexOf('username contains inappropriate')!==-1&&!isPub&&nameOverlay){
              storedName=''; try{localStorage.removeItem(LS_NAME);}catch(e){}
              if(nameInput){nameInput.value='';nameInput.readOnly=false;nameInput.style.opacity='';nameInput.style.cursor='';nameInput.title='';}
              showNameErr('That username is not allowed — please choose another.');
              if(nameModal) nameModal.value=''; nameOverlay.classList.add('active'); if(nameModal) nameModal.focus();
              _pendingPost=doPost;
            }
          }
          submitBtn.disabled=false; submitBtn.innerHTML='<i class="fas fa-paper-plane" style="font-size:.7rem"></i> Post'; updatePostBtn();
        }).catch(function(){ showErr('Network error. Try again.'); submitBtn.disabled=false; submitBtn.innerHTML='<i class="fas fa-paper-plane" style="font-size:.7rem"></i> Post'; updatePostBtn(); });
    }
    if(submitBtn){
      submitBtn.addEventListener('click',function(){
        if(!isPub&&!storedName){ if(nameOverlay){ if(nameModal) nameModal.value=''; nameOverlay.classList.add('active'); if(nameModal) nameModal.focus(); } _pendingPost=doPost; return; }
        doPost();
      });
    }
    load();
  })();
})();
</script>
</body>
</html>
<?php
   exit;
  } // end else (valid record)
 } // end if ($mlpsht !== '')

$share_code = get_query_var('mlp_share');
if ($share_code) {
 global $wpdb;
 $table_name = $wpdb->prefix . 'mlp_shared_codes';
 $table_exists_h = wp_cache_get( 'mlp_share_table_exists', 'mlp_schema' );
 if ( $table_exists_h === false ) {
 $table_exists_h = ( $wpdb->get_var( $wpdb->prepare( 'SHOW TABLES LIKE %s', $table_name ) ) === $table_name ) ? 1 : 0;
 wp_cache_set( 'mlp_share_table_exists', $table_exists_h, 'mlp_schema', 3600 );
 }
 if ( ! $table_exists_h ) {
 $this->create_share_table();
 wp_cache_set( 'mlp_share_table_exists', 1, 'mlp_schema', 3600 );
 }
 // Only select the columns we actually use — avoids fetching the full tab_data blob unnecessarily.
 $share_data = $wpdb->get_row($wpdb->prepare(
    "SELECT share_code, tab_name, tab_data, shared_by, expires_at, created_at FROM $table_name WHERE share_code = %s LIMIT 1",
 $share_code
 ));
 if ($share_data) {
 $is_expired   = strtotime($share_data->expires_at) <= time();
 $project_name = $share_data->tab_name;
 $raw_tabs     = json_decode($share_data->tab_data, true);

 // Normalise tab_data into a flat array: [{name, content, lang}, ...]
 // The frontend can send either an array of tab objects or a keyed object.
 $tabs = array();
 if (is_array($raw_tabs)) {
     if (isset($raw_tabs[0]) && is_array($raw_tabs[0])) {
         // Already an indexed array of tab objects
         foreach ($raw_tabs as $t) {
             $tabs[] = array(
                 'name'    => isset($t['name'])    ? $t['name']    : 'Tab',
                 'content' => isset($t['content']) ? $t['content'] : '',
                 'lang'    => isset($t['lang'])    ? $t['lang']    : (isset($t['type']) ? $t['type'] : 'html'),
             );
         }
     } elseif (isset($raw_tabs['tabs']) && is_array($raw_tabs['tabs'])) {
         // Object with a 'tabs' key
         foreach ($raw_tabs['tabs'] as $t) {
             $tabs[] = array(
                 'name'    => isset($t['name'])    ? $t['name']    : 'Tab',
                 'content' => isset($t['content']) ? $t['content'] : '',
                 'lang'    => isset($t['lang'])    ? $t['lang']    : (isset($t['type']) ? $t['type'] : 'html'),
             );
         }
     } else {
         // Flat associative object: {html: '...', css: '...', js: '...', ...}
         $lang_map = array('html'=>'html','css'=>'css','js'=>'js','javascript'=>'js');
         foreach ($raw_tabs as $key => $val) {
             $tabs[] = array(
                 'name'    => strtoupper($key),
                 'content' => is_string($val) ? $val : '',
                 'lang'    => isset($lang_map[strtolower($key)]) ? $lang_map[strtolower($key)] : strtolower($key),
             );
         }
     }
 }

 // Fallback: at least show HTML/CSS/JS empty tabs
 if (empty($tabs)) {
     $tabs = array(
         array('name'=>'HTML','content'=>'','lang'=>'html'),
         array('name'=>'CSS', 'content'=>'','lang'=>'css'),
         array('name'=>'JS',  'content'=>'','lang'=>'js'),
     );
 }

 // Build JSON payloads for JS
 $js_tabs         = wp_json_encode($tabs);
 $js_project_name = wp_json_encode($project_name);
 $js_share_code   = wp_json_encode($share_code);
 $js_expires      = (int) strtotime($share_data->expires_at);
 $js_ajax_url_p2  = wp_json_encode( admin_url('admin-ajax.php') );
 $js_share_nonce_p2 = wp_json_encode( is_user_logged_in() ? wp_create_nonce('mlp_share_project') : '' );
 $js_reactions_p2 = wp_json_encode( array('likes' => intval($share_data->likes ?? 0), 'made' => intval($share_data->made ?? 0)) );
$_likes_p2    = intval($share_data->likes ?? 0);
$_dislikes_p2 = intval($share_data->made ?? 0);
$js_comment_nonce_p2 = wp_json_encode( wp_create_nonce('mlp_comment_nonce') );
$js_pub_token_p2     = wp_json_encode( $this->mlp_pub_token( $share_code ) );
$js_pub_name_p2      = wp_json_encode( '' );
 $js_is_expired   = $is_expired ? 'true' : 'false';
 $editor_url      = esc_url(home_url('/'));

 // Publisher info (viewer 2) — short-lived shares use WP user IDs, no custom username available
 $_pub_name2='';$_pub_since2='';$_pub_projects2=[];

 // Tab dot colours
 $lang_colours = array(
     'html' => '#ef4444',
     'css'  => '#06b6d4',
     'js'   => '#f59e0b',
     'javascript' => '#f59e0b',
 );

 // Suppress WP from loading any further output; emit a complete standalone page.
 nocache_headers();
 status_header(200);

 echo '<!DOCTYPE html>' . "\n";
 echo '<html lang="en">' . "\n";
 echo '<head>' . "\n";
 echo '<meta charset="UTF-8">' . "\n";
 echo '<meta name="viewport" content="width=device-width, initial-scale=1">' . "\n";
 echo '<title>' . esc_html($project_name) . ' — Pterocose</title>' . "\n";
 echo '<link href="https://fonts.googleapis.com/css2?family=Syne:wght@400;600;700;800&family=JetBrains+Mono:wght@400;500;700&display=swap" rel="stylesheet">' . "\n";
 echo '<link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.5.1/css/all.min.css">' . "\n";
 ?>
<style>
*,*::before,*::after{box-sizing:border-box}
:root{
  --bg:#f5f7fb;--surface:#ffffff;--surface2:#f8f9fc;
  --border:#e2e8f0;--accent:#ea580c;--text:#1a1a2e;
  --muted:#6b6b8a;--muted2:#8a8aa8;--sw:200px;--th:52px;
}
html,body{margin:0;padding:0;background:var(--bg);color:var(--text);font-family:'Syne',sans-serif;min-height:100vh}

/* ── SIDEBAR ── */
.sidebar{position:fixed;top:0;left:0;bottom:0;width:var(--sw);background:var(--bg);border-right:1px solid var(--border);display:flex;flex-direction:column;z-index:300;overflow-y:auto}
.sb-logo{display:flex;align-items:center;justify-content:center;padding:18px 14px;min-height:90px;border-bottom:1px solid var(--border);text-decoration:none;gap:8px}
.sb-logo-text{font-weight:800;font-size:1.15rem;color:var(--text);letter-spacing:-.03em}
.sb-logo-text span{background:linear-gradient(135deg,#ea580c,#f97316,#fdba74);-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text}
.sb-label{font-size:.6rem;font-weight:700;letter-spacing:.1em;text-transform:uppercase;color:var(--accent);padding:14px 14px 5px}
.sb-nav{display:flex;flex-direction:column;gap:1px;padding:4px 8px}
.sb-nav a,.sb-nav button{display:flex;align-items:center;gap:9px;padding:8px 9px;border-radius:7px;color:#4a4a6a;text-decoration:none;font-size:.85rem;font-weight:600;background:transparent;border:none;cursor:pointer;width:100%;text-align:left;font-family:'Syne',sans-serif;transition:background .15s,color .15s}
.sb-nav a:hover,.sb-nav button:hover{background:rgba(234,88,12,.08);color:var(--accent)}
.sb-nav a.active{background:rgba(234,88,12,.12);color:var(--accent);border-left:2px solid var(--accent)}
.sb-divider{height:1px;background:var(--border);margin:6px 12px}
.sb-fork{display:flex;align-items:center;justify-content:center;gap:8px;margin:0 10px 10px;padding:10px 12px;background:linear-gradient(135deg,#ea580c,#c2410c);color:#fff;border:none;border-radius:8px;font-size:.82rem;font-weight:700;cursor:pointer;font-family:'Syne',sans-serif;box-shadow:0 2px 8px rgba(234,88,12,.25);transition:opacity .15s,transform .1s;width:calc(100% - 20px)}
.sb-fork:hover{opacity:.92;transform:translateY(-1px)}
.sb-ver{margin-top:auto;padding:16px 14px 20px;font-size:.65rem;color:var(--muted);font-family:'JetBrains Mono',monospace;opacity:.8;text-align:center;border-top:1px solid var(--border)}
.sb-react-wrap{padding:0 10px 6px}
.sb-react-btns{display:flex;gap:8px;padding:0 4px}
.sb-react-btn{flex:1;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:3px;padding:9px 6px;border-radius:9px;border:1.5px solid var(--border);background:transparent;cursor:pointer;font-family:'Syne',sans-serif;transition:background .15s,border-color .15s,transform .1s;color:var(--text)}
.sb-react-btn:hover{background:rgba(234,88,12,.08);border-color:var(--accent);transform:translateY(-1px)}
.sb-react-btn.sb-react-on{border-color:var(--accent);background:rgba(234,88,12,.12);color:var(--accent)}
.sb-react-emoji{font-size:1.2rem;line-height:1}
.sb-react-num{font-size:.82rem;font-weight:700;line-height:1}
.sb-react-lbl{font-size:.6rem;font-weight:600;letter-spacing:.04em;text-transform:uppercase;opacity:.7;line-height:1}

/* ── SHELL ── */
.shell{margin-left:var(--sw);display:flex;flex-direction:column;min-height:100vh}

/* ── TOPBAR ── */
.topbar{position:sticky;top:0;z-index:200;height:var(--th);background:var(--bg);border-bottom:1px solid var(--border);display:flex;align-items:center;gap:10px;padding:0 20px}
.tb-name{font-size:.92rem;font-weight:700;color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;flex:1;min-width:0}
.tb-badge{display:inline-flex;align-items:center;padding:2px 9px;border-radius:100px;background:rgba(5,150,105,.1);color:#059669;font-size:.62rem;font-weight:700;letter-spacing:.06em;text-transform:uppercase;white-space:nowrap;flex-shrink:0}
.tb-badge.expired{background:rgba(220,38,38,.1);color:#dc2626}
.tb-gap{flex:1}
.btn-ghost{display:inline-flex;align-items:center;gap:6px;padding:6px 14px;background:transparent;border:1px solid var(--border);border-radius:7px;color:#4a4a6a;font-family:'Syne',sans-serif;font-size:.79rem;font-weight:600;text-decoration:none;cursor:pointer;transition:border-color .15s,background .15s,color .15s;white-space:nowrap}
.btn-ghost:hover{border-color:var(--accent);background:rgba(234,88,12,.05);color:var(--accent)}

/* ── TABS BAR ── */
.tabs-bar{display:flex;align-items:center;gap:2px;padding:8px 20px 0;border-bottom:1px solid var(--border);background:var(--bg);overflow-x:auto}
.tab-btn{display:flex;align-items:center;gap:7px;padding:7px 14px;border-radius:8px 8px 0 0;border:1px solid transparent;border-bottom:none;font-family:'JetBrains Mono',monospace;font-size:.72rem;font-weight:600;cursor:pointer;background:transparent;color:var(--muted);transition:background .15s,color .15s;position:relative;bottom:-1px;white-space:nowrap}
.tab-btn:hover{background:var(--surface);color:var(--text)}
.tab-btn.active{background:var(--surface);border-color:var(--border);color:var(--text);border-bottom-color:var(--surface)}
.tab-dot{width:8px;height:8px;border-radius:50%;flex-shrink:0}

/* ── CONTENT AREA ── */
.content-wrap{flex:1;display:flex;flex-direction:column;gap:0;background:var(--bg)}
.pane{display:none;padding:20px 20px 0}
.pane.active{display:block}

/* ── CODE CARD ── */
.code-card{background:var(--surface);border:1px solid var(--border);border-radius:10px;overflow:hidden;box-shadow:0 1px 3px rgba(0,0,0,.04);margin-bottom:0}
.cc-header{display:flex;align-items:center;gap:8px;padding:10px 14px;background:var(--surface2);border-bottom:1px solid var(--border)}
.cc-title{font-family:'JetBrains Mono',monospace;font-size:.7rem;font-weight:700;color:var(--muted);text-transform:uppercase;letter-spacing:.06em;flex:1}
.cc-lines{font-size:.63rem;color:var(--muted2);font-family:'JetBrains Mono',monospace}
.cc-body{overflow:auto;max-height:340px}
pre.code-pre{margin:0;padding:14px 16px;font-family:'JetBrains Mono',monospace;font-size:.72rem;line-height:1.8;color:var(--text);background:#fafbfd;white-space:pre;tab-size:2;overflow:visible}

/* ── PREVIEW SECTION ── */
.preview-section{margin:20px;border:1px solid var(--border);border-radius:10px;overflow:hidden;background:var(--surface);box-shadow:0 1px 3px rgba(0,0,0,.04);flex-shrink:0}
.pv-header{display:flex;align-items:center;gap:8px;padding:10px 14px;background:var(--surface2);border-bottom:1px solid var(--border)}
.pv-dots{display:flex;gap:6px;margin-right:4px}
.pv-dot{width:10px;height:10px;border-radius:50%}
.pv-title{font-size:.75rem;font-weight:700;color:var(--muted);flex:1;text-transform:uppercase;letter-spacing:.06em}
.pv-btn{display:inline-flex;align-items:center;gap:5px;padding:4px 11px;background:transparent;border:1px solid var(--border);border-radius:6px;font-size:.7rem;font-weight:600;color:#4a4a6a;cursor:pointer;font-family:'Syne',sans-serif;transition:border-color .15s,color .15s,background .15s}
.pv-btn:hover{border-color:var(--accent);color:var(--accent);background:rgba(234,88,12,.05)}
.pv-iframe-wrap{position:relative;width:100%;height:380px;background:#fff}
.pv-iframe{width:100%;height:100%;border:none;display:block}

/* ── FULLSCREEN ── */
.fs-overlay{display:none;position:fixed;inset:0;z-index:9999;flex-direction:column;background:#000}
.fs-overlay.active{display:flex}
.fs-bar{display:flex;align-items:center;gap:10px;padding:10px 16px;background:var(--bg);border-bottom:1px solid var(--border)}
.fs-title{font-size:.85rem;font-weight:700;color:var(--text);flex:1}
.fs-iframe{flex:1;border:none;width:100%}

/* ── EXPIRED BANNER ── */
.expired-banner{display:flex;align-items:center;gap:10px;margin:16px 20px 0;padding:11px 16px;background:rgba(220,38,38,.07);border:1px solid rgba(220,38,38,.2);border-radius:8px;font-size:.8rem;color:#b91c1c;font-weight:600}

/* ── TOAST ── */
.toast{position:fixed;bottom:24px;right:24px;z-index:10000;background:var(--surface);border:1px solid var(--border);border-radius:10px;padding:13px 17px;box-shadow:0 8px 24px rgba(0,0,0,.1);display:flex;align-items:center;gap:10px;font-size:.82rem;font-weight:600;color:var(--text);opacity:0;transform:translateY(10px);transition:opacity .25s,transform .25s;pointer-events:none}
.toast.show{opacity:1;transform:translateY(0)}
.toast-icon{width:26px;height:26px;border-radius:50%;background:linear-gradient(135deg,#ea580c,#c2410c);display:flex;align-items:center;justify-content:center;color:#fff;font-size:.72rem;flex-shrink:0}

@media(max-width:700px){:root{--sw:0px}.sidebar{display:none}}
.sb-pub{padding:10px 14px 12px}
.sb-pub-name{font-size:.8rem;font-weight:700;color:var(--text);margin-bottom:2px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}
.sb-pub-since{font-size:.62rem;color:var(--muted);font-family:'JetBrains Mono',monospace;margin-bottom:8px}
.sb-pub-more{display:flex;align-items:center;justify-content:center;gap:6px;width:100%;padding:7px 10px;background:transparent;border:1px solid var(--border);border-radius:7px;font-size:.75rem;font-weight:600;color:#4a4a6a;cursor:pointer;font-family:'Syne',sans-serif;transition:border-color .15s,color .15s,background .15s}
.sb-pub-more:hover{border-color:var(--accent);color:var(--accent);background:rgba(234,88,12,.05)}
.pub-projects-overlay{display:none;position:fixed;inset:0;z-index:400;background:var(--bg);flex-direction:column}
