<script>
(function () {
  var TABS        = <?php echo $js_tabs; ?>;
  var PROJ_NAME   = <?php echo $js_project_name; ?>;
  var SHARE_CODE  = <?php echo $js_share_code; ?>;
  var IS_EXPIRED  = <?php echo $js_is_expired; ?>;
  var LS_KEY      = 'mlp_projects';

  /* ── build preview srcdoc ── */
  function buildSrcdoc() {
    var html = '', css = '', js = '';
    TABS.forEach(function (t) {
      var l = (t.lang || '').toLowerCase();
      if (l === 'html')                  html = t.content;
      else if (l === 'css')              css  = t.content;
      else if (l === 'js' || l === 'javascript') js = t.content;
    });
    var doc = html || '<!DOCTYPE html><html><head></head><body></body></html>';
    if (css) {
      if (doc.indexOf('</head>') !== -1) {
        doc = doc.replace('</head>', '<style>' + css + '</style></head>');
      } else {
        doc = '<style>' + css + '</style>' + doc;
      }
    }
    if (js) {
      if (doc.indexOf('</body>') !== -1) {
        doc = doc.replace('</body>', '<script>' + js + '<\/script></body>');
      } else {
        doc = doc + '<script>' + js + '<\/script>';
      }
    }
    return doc;
  }

  function loadPreview(iframe) {
    iframe.srcdoc = buildSrcdoc();
  }

  /* ── tab switching ── */
  var tabBtns = document.querySelectorAll('.tab-btn');
  var panes   = document.querySelectorAll('.pane');
  tabBtns.forEach(function (btn) {
    btn.addEventListener('click', function () {
      var idx = btn.getAttribute('data-tab');
      tabBtns.forEach(function (b) { b.classList.remove('active'); });
      panes.forEach(function (p) { p.classList.remove('active'); });
      btn.classList.add('active');
      var p = document.getElementById('pane-' + idx);
      if (p) p.classList.add('active');
    });
  });

  /* ── preview load ── */
  var previewIframe = document.getElementById('mlp-preview-iframe');
  loadPreview(previewIframe);
  document.getElementById('mlp-refresh-btn').addEventListener('click', function () {
    loadPreview(previewIframe);
  });

  /* ── fullscreen ── */
  var fsOverlay = document.getElementById('mlp-fs-overlay');
  var fsIframe  = document.getElementById('mlp-fs-iframe');
  document.getElementById('mlp-fs-btn').addEventListener('click', function () {
    loadPreview(fsIframe);
    fsOverlay.classList.add('active');
  });
  document.getElementById('mlp-fs-close').addEventListener('click', function () {
    fsOverlay.classList.remove('active');
    fsIframe.srcdoc = '';
  });

  /* ── toast helper ── */
  var toastEl  = document.getElementById('mlp-toast');
  var toastMsg = document.getElementById('mlp-toast-msg');
  function showToast(msg) {
    toastMsg.textContent = msg;
    toastEl.classList.add('show');
    setTimeout(function () { toastEl.classList.remove('show'); }, 3200);
  }

  /* ── Add to My Projects ── */
  document.getElementById('mlp-fork-btn').addEventListener('click', function () {
    try {
      var projects = [];
      try {
        var raw = localStorage.getItem(LS_KEY);
        if (raw) {
          var parsed = JSON.parse(raw);
          if (Array.isArray(parsed)) projects = parsed;
        }
      } catch (e) {}

      // Build a new project object matching the mlp_projects schema
      var newProject = {
        id:         'fork_' + SHARE_CODE + '_' + Date.now(),
        name:       PROJ_NAME + ' (fork)',
        tabs:       TABS.map(function (t) {
                      return { name: t.name, content: t.content, lang: t.lang };
                    }),
        activeTab:  0,
        created:    Date.now(),
        forkedFrom: SHARE_CODE,
        isPrivate:  true
      };

      projects.push(newProject);
      localStorage.setItem(LS_KEY, JSON.stringify(projects));
      showToast('Added "' + PROJ_NAME + '" to your projects!');
    } catch (e) {
      showToast('Could not save — localStorage may be full.');
    }
  });

  // ── Like / Dislike reactions ──
  (function(){
    var AJAX_URL   = <?php echo $js_ajax_url_p2; ?>;
    var NONCE      = <?php echo $js_share_nonce_p2; ?>;
    var likeBtn    = document.getElementById('mlp-like-btn');
    var dislikeBtn = document.getElementById('mlp-dislike-btn');
    if (!likeBtn || !dislikeBtn) return;
    function sendReaction(kind, state){
      if (!window.fetch || !AJAX_URL || !SHARE_CODE) return;
      var fd = new FormData();
      fd.append('action',   'mlp_react_to_share');
      fd.append('nonce',    NONCE);
      fd.append('token',    SHARE_CODE);
      fd.append('reaction', kind === 'dislike' ? 'made' : 'like');
      fd.append('state',    state ? '1' : '0');
      fetch(AJAX_URL, {method:'POST',body:fd,credentials:'same-origin'}).catch(function(){});
    }
    [likeBtn, dislikeBtn].forEach(function(btn){
      btn.addEventListener('click', function(){
        var kind  = btn.getAttribute('data-kind');
        var isOn  = btn.classList.contains('sb-react-on');
        var other = kind === 'like' ? dislikeBtn : likeBtn;
        if (other.classList.contains('sb-react-on')) {
          other.classList.remove('sb-react-on');
          sendReaction(kind === 'like' ? 'dislike' : 'like', false);
          var otherStat = document.getElementById(kind === 'like' ? 'mlp-stat-dislikes' : 'mlp-stat-likes');
          if(otherStat){ otherStat.textContent = Math.max(0, parseInt(otherStat.textContent,10)-1); }
        }
        if (isOn) {
          btn.classList.remove('sb-react-on');
          sendReaction(kind, false);
          var st = document.getElementById(kind === 'like' ? 'mlp-stat-likes' : 'mlp-stat-dislikes');
          if(st){ st.textContent = Math.max(0, parseInt(st.textContent,10)-1); }
        } else {
          btn.classList.add('sb-react-on');
          sendReaction(kind, true);
          var st2 = document.getElementById(kind === 'like' ? 'mlp-stat-likes' : 'mlp-stat-dislikes');
          if(st2){ st2.textContent = parseInt(st2.textContent,10)+1; }
        }
      });
    });
  })();

  // ── Comments ──
  (function(){
    var AJAX_URL = <?php echo $js_ajax_url_p2; ?>;
    var CNONCE   = <?php echo $js_comment_nonce_p2; ?>;
    var PUB_TOK  = <?php echo $js_pub_token_p2; ?>;
    var PUB_NAME = <?php echo $js_pub_name_p2; ?>;
    var ID       = SHARE_CODE;
    var LS_NAME  = 'mlp_commenter_name';
    var LS_CID   = 'mlp_commenter_id';
    var RL_KEY   = 'mlp_cmt_last_' + ID;

    var cmtId = '';
    try { cmtId = localStorage.getItem(LS_CID) || ''; } catch(e){}
    if (!cmtId) {
      cmtId = 'c' + Math.random().toString(36).slice(2,16) + Date.now().toString(36);
      try { localStorage.setItem(LS_CID, cmtId); } catch(e){}
    }

    var isPub = false;
    try {
      var _pp = JSON.parse(localStorage.getItem('mlp_projects')||'[]');
      isPub = Array.isArray(_pp) && _pp.some(function(p){ return p.shareToken === ID; });
    } catch(e){}

    var storedName = '';
    try { storedName = localStorage.getItem(LS_NAME) || ''; } catch(e){}

    var nameInput      = document.getElementById('mlp-comment-name');
    var submitBtn      = document.getElementById('mlp-comment-submit');
    var nameOverlay    = document.getElementById('mlp-name-overlay');
    var nameModal      = document.getElementById('mlp-name-input');
    var nameConfirmBtn = document.getElementById('mlp-name-confirm');
    var nameErrEl      = document.getElementById('mlp-name-err');
    var errEl          = document.getElementById('mlp-comment-err');
    var _editMode = false; var _editIdx = -1; var _sortedCache = []; var _pendingPost = null;

    function showErr(m){ if(errEl){errEl.textContent=m;errEl.style.display=m?'block':'none';} }
    function showNameErr(m){ if(nameErrEl){nameErrEl.textContent=m;nameErrEl.style.display=m?'block':'none';} }
    function updatePostBtn(){
      if (!submitBtn || _editMode) return;
      var ok = isPub || !!storedName;
      submitBtn.disabled = !ok; submitBtn.style.opacity = ok ? '' : '0.5';
      submitBtn.title = ok ? '' : 'Set a username first';
    }

    if (isPub) {
      if (nameInput) { nameInput.value = PUB_NAME || storedName || 'Publisher'; nameInput.readOnly = true; nameInput.style.opacity='0.65'; nameInput.style.cursor='not-allowed'; nameInput.title='Publisher name — cannot be changed'; }
      if (submitBtn) { submitBtn.disabled = false; submitBtn.style.opacity = ''; }
    } else {
      if (storedName && nameInput) { nameInput.value = storedName; nameInput.readOnly = true; nameInput.style.opacity='0.65'; nameInput.style.cursor='not-allowed'; nameInput.title='Username is permanent'; }
      updatePostBtn();
    }

    if (nameConfirmBtn) nameConfirmBtn.addEventListener('click', function(){
      var n = (nameModal ? nameModal.value : '').trim();
      if (!n) { showNameErr('Please enter a username.'); return; }
      if (n.length < 2) { showNameErr('At least 2 characters required.'); return; }
      storedName = n;
      try { localStorage.setItem(LS_NAME, n); } catch(e){}
      if (nameInput) { nameInput.value = n; nameInput.readOnly = true; nameInput.style.opacity='0.65'; nameInput.style.cursor='not-allowed'; nameInput.title='Username is permanent'; }
      if (nameOverlay) nameOverlay.classList.remove('active');
      showNameErr(''); updatePostBtn();
      if (typeof _pendingPost === 'function') { _pendingPost(); _pendingPost = null; }
    });
    if (nameModal) nameModal.addEventListener('keydown', function(e){ if (e.key==='Enter'&&nameConfirmBtn) nameConfirmBtn.click(); });

    var writeToggle = document.getElementById('mlp-write-toggle');
    var commentForm = document.getElementById('mlp-comment-form');
    if (writeToggle && commentForm) {
      writeToggle.addEventListener('click', function(){
        if (_editMode) { cancelEdit(); return; }
        if (!isPub && !storedName) {
          if (nameOverlay) { if (nameModal) nameModal.value=''; nameOverlay.classList.add('active'); if (nameModal) nameModal.focus(); }
          return;
        }
        var open = commentForm.style.display !== 'none';
        commentForm.style.display = open ? 'none' : 'block';
        writeToggle.innerHTML = open ? '<i class="fas fa-plus" style="font-size:.6rem"></i> Write' : '<i class="fas fa-times" style="font-size:.6rem"></i> Close';
      });
    }

    function esc(s){ return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }
    function timeAgo(ts){ var d=Math.floor(Date.now()/1000)-ts; if(d<60) return d+'s ago'; if(d<3600) return Math.floor(d/60)+'m ago'; if(d<86400) return Math.floor(d/3600)+'h ago'; return Math.floor(d/86400)+'d ago'; }
    function sortComments(arr){
      var pinned=[],pubC=[],rest=[];
      arr.forEach(function(c,i){ c._i=i; });
      arr.forEach(function(c){ if(c.is_pinned) pinned.push(c); else if(c.is_publisher) pubC.push(c); else rest.push(c); });
      return pinned.concat(pubC,rest.slice().reverse());
    }

    function render(comments){
      _sortedCache=[];
      var list=document.getElementById('mlp-comments-list'), countEl=document.getElementById('mlp-comments-count');
      var cnt=comments?comments.length:0;
      if(countEl) countEl.innerHTML='<i class="fas fa-comments" style="font-size:.65rem"></i> '+cnt+' Comment'+(cnt===1?'':'s');
      if(!list) return;
      if(!comments||!cnt){ list.innerHTML='<div class="sb-comment-empty">No comments yet. Be the first!</div>'; return; }
      var sorted=sortComments(comments.slice()); _sortedCache=sorted; var html='';
      sorted.forEach(function(c){
        var cls='sb-comment-item';
        if(c.is_publisher) cls+=' sb-comment-publisher';
        if(c.is_pinned) cls+=' sb-comment-pinned';
        var pinBtn=isPub?'<button class="sb-pin-btn'+(c.is_pinned?' pinned':'')+'" data-idx="'+c._i+'" title="'+(c.is_pinned?'Unpin':'Pin to top')+'">📌</button>':'';
        var pinBadge=c.is_pinned?'<span class="sb-pin-badge" title="Pinned">📌</span>':'';
        var pubBadge=c.is_publisher?'<span class="sb-comment-pub-badge">Publisher</span>':'';
        var editedTag=c.edited?' <span style="font-size:.58rem;color:var(--muted2)">(edited)</span>':'';
        var actions='';
        if(c.is_own||isPub){
          actions+='<button class="sb-cmt-act" data-action="edit" data-idx="'+c._i+'" title="Edit">✏️</button>';
          actions+='<button class="sb-cmt-act" data-action="delete" data-idx="'+c._i+'" title="Delete">🗑️</button>';
        }
        html+='<div class="'+cls+'">'
          +'<div style="display:flex;align-items:center;justify-content:space-between;gap:4px">'
          +'<div class="sb-comment-author'+(c.is_publisher?' sb-comment-pub-author':'')+'">'+esc(c.name)+pubBadge+pinBadge+'</div>'
          +'<div style="display:flex;gap:2px;flex-shrink:0">'+pinBtn+actions+'</div>'
          +'</div>'
          +'<div class="sb-comment-text">'+esc(c.text)+editedTag+'</div>'
          +'<div class="sb-comment-time">'+timeAgo(c.time)+'</div>'
          +'</div>';
      });
      list.innerHTML=html;
      list.querySelectorAll('.sb-pin-btn').forEach(function(btn){ btn.addEventListener('click',function(){ pinComment(parseInt(btn.getAttribute('data-idx'),10)); }); });
      list.querySelectorAll('.sb-cmt-act').forEach(function(btn){
        btn.addEventListener('click',function(){
          var action=btn.getAttribute('data-action'), idx=parseInt(btn.getAttribute('data-idx'),10);
          if(action==='delete') deleteComment(idx); else if(action==='edit') startEdit(idx);
        });
      });
      list.scrollTop=list.scrollHeight;
    }

    function load(){
      if(!AJAX_URL||!ID) return;
      fetch(AJAX_URL+'?action=mlp_get_comments&id='+encodeURIComponent(ID)+'&cmt_id='+encodeURIComponent(cmtId),{credentials:'same-origin'})
        .then(function(r){return r.json();}).then(function(d){if(d.success) render(d.data.comments);}).catch(function(){});
    }
    function pinComment(idx){
      if(!AJAX_URL||!ID||!PUB_TOK) return;
      var fd=new FormData(); fd.append('action','mlp_pin_comment'); fd.append('nonce',CNONCE); fd.append('id',ID); fd.append('index',idx); fd.append('pub_token',PUB_TOK);
      fetch(AJAX_URL,{method:'POST',body:fd,credentials:'same-origin'}).then(function(r){return r.json();}).then(function(d){if(d.success) load();}).catch(function(){});
    }
    function deleteComment(idx){
      if(!AJAX_URL||!ID) return;
      if(!confirm('Delete this comment?')) return;
      var fd=new FormData(); fd.append('action','mlp_delete_comment'); fd.append('nonce',CNONCE); fd.append('id',ID); fd.append('index',idx);
      if(isPub) fd.append('pub_token',PUB_TOK); else fd.append('cmt_id',cmtId);
      fetch(AJAX_URL,{method:'POST',body:fd,credentials:'same-origin'})
        .then(function(r){return r.json();}).then(function(d){ if(d.success) load(); else showErr((d.data&&d.data.message)||'Could not delete.'); }).catch(function(){});
    }
    function startEdit(idx){
      var c=_sortedCache.find(function(x){ return x._i===idx; }); if(!c) return;
      var textEl=document.getElementById('mlp-comment-text'); if(!textEl) return;
      _editMode=true; _editIdx=idx; textEl.value=c.text;
      if(commentForm) commentForm.style.display='block';
      if(writeToggle) writeToggle.innerHTML='<i class="fas fa-times" style="font-size:.6rem"></i> Close';
      if(submitBtn){ submitBtn.disabled=false; submitBtn.innerHTML='<i class="fas fa-save" style="font-size:.7rem"></i> Save Edit'; }
      showErr('Editing — click Close to cancel.');
    }
    function cancelEdit(){
      _editMode=false; _editIdx=-1;
      var textEl=document.getElementById('mlp-comment-text'); if(textEl) textEl.value='';
      if(submitBtn) submitBtn.innerHTML='<i class="fas fa-paper-plane" style="font-size:.7rem"></i> Post';
      if(commentForm) commentForm.style.display='none';
      if(writeToggle) writeToggle.innerHTML='<i class="fas fa-plus" style="font-size:.6rem"></i> Write';
      showErr(''); updatePostBtn();
    }
    function doPost(){
      var name=isPub?(PUB_NAME||storedName||'Publisher'):storedName;
      var text=(document.getElementById('mlp-comment-text')||{}).value||'';
      if(!text.trim()){ showErr('Please write something first.'); return; }
      if(!name){ showErr('Please set a username first.'); return; }
      if(!_editMode){
        var lastPost=0; try{ lastPost=parseInt(localStorage.getItem(RL_KEY)||'0',10)||0; }catch(e){}
        if(lastPost&&(Date.now()-lastPost)<600000){ var wait=Math.ceil((600000-(Date.now()-lastPost))/60000); showErr('Please wait '+wait+' more minute'+(wait===1?'':'s')+' before posting again.'); return; }
      }
      submitBtn.disabled=true; submitBtn.innerHTML='<i class="fas fa-spinner fa-spin" style="font-size:.7rem"></i> '+(_editMode?'Saving...':'Posting...');
      if(_editMode){
        var fd=new FormData(); fd.append('action','mlp_edit_comment'); fd.append('nonce',CNONCE); fd.append('id',ID); fd.append('index',_editIdx); fd.append('text',text);
        if(isPub) fd.append('pub_token',PUB_TOK); else fd.append('cmt_id',cmtId);
        fetch(AJAX_URL,{method:'POST',body:fd,credentials:'same-origin'})
          .then(function(r){return r.json();}).then(function(d){
            if(d.success){ cancelEdit(); load(); }
            else{ showErr((d.data&&d.data.message)||'Could not save.'); submitBtn.disabled=false; submitBtn.innerHTML='<i class="fas fa-save" style="font-size:.7rem"></i> Save Edit'; }
          }).catch(function(){ showErr('Network error.'); submitBtn.disabled=false; submitBtn.innerHTML='<i class="fas fa-save" style="font-size:.7rem"></i> Save Edit'; });
        return;
      }
      var fd=new FormData(); fd.append('action','mlp_post_comment'); fd.append('nonce',CNONCE);
      fd.append('id',ID); fd.append('name',name); fd.append('text',text); fd.append('cmt_id',cmtId);
      if(isPub) fd.append('pub_token',PUB_TOK);
      fetch(AJAX_URL,{method:'POST',body:fd,credentials:'same-origin'})
        .then(function(r){return r.json();}).then(function(d){
          if(d.success){ document.getElementById('mlp-comment-text').value=''; showErr(''); try{ localStorage.setItem(RL_KEY,String(Date.now())); }catch(e){} load(); }
          else{
            var msg=(d.data&&d.data.message)||'Could not post comment.';
            showErr(msg);
            if(msg.indexOf('username contains inappropriate')!==-1&&!isPub&&nameOverlay){
              storedName=''; try{localStorage.removeItem(LS_NAME);}catch(e){}
              if(nameInput){nameInput.value='';nameInput.readOnly=false;nameInput.style.opacity='';nameInput.style.cursor='';nameInput.title='';}
              showNameErr('That username is not allowed — please choose another.');
              if(nameModal) nameModal.value=''; nameOverlay.classList.add('active'); if(nameModal) nameModal.focus();
              _pendingPost=doPost;
            }
          }
          submitBtn.disabled=false; submitBtn.innerHTML='<i class="fas fa-paper-plane" style="font-size:.7rem"></i> Post'; updatePostBtn();
        }).catch(function(){ showErr('Network error. Try again.'); submitBtn.disabled=false; submitBtn.innerHTML='<i class="fas fa-paper-plane" style="font-size:.7rem"></i> Post'; updatePostBtn(); });
    }
    if(submitBtn){
      submitBtn.addEventListener('click',function(){
        if(!isPub&&!storedName){ if(nameOverlay){ if(nameModal) nameModal.value=''; nameOverlay.classList.add('active'); if(nameModal) nameModal.focus(); } _pendingPost=doPost; return; }
        doPost();
      });
    }
    load();
  })();
})();
</script>
</body>
</html>
<?php
 exit;
 } else {
 // Share code not found in DB — show the Pterocose "gone" page.
 while ( ob_get_level() > 0 ) { ob_end_clean(); }
 nocache_headers();
 status_header( 410 );
 echo mlp_pterocose_gone_page( $share_code );
 exit;
 }
}
 }
 private function mlp_pub_token( $identifier ) {
  return substr( hash( 'sha256', 'mlp_pub_v1|' . $identifier . '|' . ( defined('AUTH_KEY') ? AUTH_KEY : wp_salt() ) ), 0, 24 );
 }
 public function ajax_post_comment() {
  if (!isset($_POST['nonce']) || !wp_verify_nonce($_POST['nonce'], 'mlp_comment_nonce')) {
   wp_send_json_error(array('message'=>'Security check failed.'), 403);
  }
  $identifier = sanitize_text_field(wp_unslash(isset($_POST['id']) ? $_POST['id'] : ''));
  $name = sanitize_text_field(wp_unslash(isset($_POST['name']) ? $_POST['name'] : ''));
  $text = sanitize_textarea_field(wp_unslash(isset($_POST['text']) ? $_POST['text'] : ''));
  $pub_token = sanitize_text_field(wp_unslash(isset($_POST['pub_token']) ? $_POST['pub_token'] : ''));
  $cmt_id_raw = sanitize_text_field(wp_unslash(isset($_POST['cmt_id']) ? $_POST['cmt_id'] : ''));
  if (empty($identifier) || empty(trim($text))) {
   wp_send_json_error(array('message'=>'Missing data.'), 400);
  }
  if (strlen($text) > 500) {
   wp_send_json_error(array('message'=>'Comment too long (max 500 characters).'), 400);
  }
  if (empty($name)) { $name = 'Anonymous'; }
  if (strlen($name) > 32) { $name = mb_substr($name, 0, 32); }
  $is_publisher = (!empty($pub_token) && $pub_token === $this->mlp_pub_token($identifier));
  if (!$is_publisher) {
   $ip = $this->get_client_ip();
   $rl_key = 'mlp_cmt_rl_' . md5($ip . $identifier);
   $rl_ts = get_transient($rl_key);
   if ($rl_ts !== false && (time() - intval($rl_ts)) < 600) {
    $wait = ceil((600 - (time() - intval($rl_ts))) / 60);
    wp_send_json_error(array('message'=>'Please wait ' . $wait . ' more minute' . ($wait === 1 ? '' : 's') . ' before posting again.'), 429);
   }
  }
  static $bad_words_regex = null;
  if ($bad_words_regex === null) {
   $bad_words_regex = '/fuck|fck|fuk|f u c k|sh[i!1]t|bitch|cunt|\bass\b|asshole|dick(?!\w)|cock(?!\w)|pussy|whore|slut|bastard|prick|twat|wank|nigger|nigga|faggot|\bfag\b|retard|kike|spic|chink|gook|rape|porn|\bsex\b|nude|naked|kill\s+you|murder|hitler|nazi|motherfucker/i';
  }
  if (preg_match($bad_words_regex, $text) || preg_match($bad_words_regex, $name)) {
   wp_send_json_error(array('message'=>'Your comment contains inappropriate language. Please keep it respectful.'), 400);
  }
  // AI username check — catches evasions and edge cases the regex misses
  if ( $name !== 'Anonymous' && $name !== '' ) {
   $cerebras_key = defined( 'MLP_CEREBRAS_API_KEY' ) ? MLP_CEREBRAS_API_KEY : '';
   $groq_key     = defined( 'MLP_GROQ_API_KEY'     ) ? MLP_GROQ_API_KEY     : '';
   if ( ! empty( $cerebras_key ) || ! empty( $groq_key ) ) {
    $name_messages = [
     [
      'role'    => 'system',
      'content' => 'You are a username moderation AI. Only reject if the username clearly contains explicit profanity, slurs, hate speech, or obvious filter evasions (e.g. "f_u_c_k", "sh1t", "n1gger"). When in doubt, PASS. Respond ONLY with JSON (no markdown): {"passed": true_or_false, "reason": "brief reason if failed, empty string if passed"}',
     ],
     [
      'role'    => 'user',
      'content' => 'Moderate this comment username: ' . $name,
     ],
    ];
    $ai_result = MLP_Projects::mlp_call_moderation_ai( $name_messages, $cerebras_key, $groq_key );
    if ( is_array( $ai_result ) && isset( $ai_result['passed'] ) && $ai_result['passed'] === false ) {
     wp_send_json_error( array( 'message' => 'Your username contains inappropriate language. Please use a different name.' ), 400 );
     return;
    }
   }
  }
  if (preg_match('/https?:\/\/(?!(?:[\w\-]+\.)*pterocos\.(?:eu\.org|com)(?:\/|$))[^\s<>"]+/i', $text)) {
   wp_send_json_error(array('message'=>'External links are not allowed. Only pterocos links are permitted.'), 400);
  }
  $option_key = 'mlp_comments_' . substr(preg_replace('/[^a-z0-9_\-]/i', '', $identifier), 0, 80);
  $comments = get_option($option_key, array());
  if (!is_array($comments)) { $comments = array(); }
  if (count($comments) >= 100) { array_shift($comments); }
  $cmt_id_hash = !empty($cmt_id_raw) ? substr(hash('sha256', $cmt_id_raw . wp_salt()), 0, 32) : '';
  $comments[] = array(
   'name'         => $name,
   'text'         => $text,
   'time'         => time(),
   'is_publisher' => $is_publisher,
   'is_pinned'    => false,
   'cmt_id_hash'  => $cmt_id_hash,
   'edited'       => false,
  );
  update_option($option_key, $comments, false);
  if (!$is_publisher) {
   set_transient($rl_key, time(), 11 * MINUTE_IN_SECONDS);
  }
  wp_send_json_success(array('message'=>'Comment posted!'));
 }
 public function ajax_get_comments() {
  $identifier = sanitize_text_field(wp_unslash(isset($_GET['id']) ? $_GET['id'] : (isset($_POST['id']) ? $_POST['id'] : '')));
  $cmt_id_raw = sanitize_text_field(wp_unslash(isset($_GET['cmt_id']) ? $_GET['cmt_id'] : (isset($_POST['cmt_id']) ? $_POST['cmt_id'] : '')));
  if (empty($identifier)) {
   wp_send_json_error(array('message'=>'Missing id.'), 400);
  }
  $option_key = 'mlp_comments_' . substr(preg_replace('/[^a-z0-9_\-]/i', '', $identifier), 0, 80);
  $comments = get_option($option_key, array());
  if (!is_array($comments)) { $comments = array(); }
  $viewer_hash = !empty($cmt_id_raw) ? substr(hash('sha256', $cmt_id_raw . wp_salt()), 0, 32) : '';
  $out = array();
  foreach (array_slice($comments, -50) as $i => $c) {
   $c['is_own'] = ($viewer_hash !== '' && !empty($c['cmt_id_hash']) && hash_equals($c['cmt_id_hash'], $viewer_hash));
   $out[] = $c;
  }
  wp_send_json_success(array('comments' => $out));
 }
 public function ajax_pin_comment() {
  if (!isset($_POST['nonce']) || !wp_verify_nonce($_POST['nonce'], 'mlp_comment_nonce')) {
   wp_send_json_error(array('message'=>'Security check failed.'), 403);
  }
  $identifier = sanitize_text_field(wp_unslash(isset($_POST['id']) ? $_POST['id'] : ''));
  $index = isset($_POST['index']) ? intval($_POST['index']) : -1;
  $pub_token = sanitize_text_field(wp_unslash(isset($_POST['pub_token']) ? $_POST['pub_token'] : ''));
  if (empty($identifier) || $index < 0 || empty($pub_token)) {
   wp_send_json_error(array('message'=>'Missing data.'), 400);
  }
  if ($pub_token !== $this->mlp_pub_token($identifier)) {
   wp_send_json_error(array('message'=>'Unauthorized.'), 403);
  }
  $option_key = 'mlp_comments_' . substr(preg_replace('/[^a-z0-9_\-]/i', '', $identifier), 0, 80);
  $comments = get_option($option_key, array());
  if (!is_array($comments) || !isset($comments[$index])) {
   wp_send_json_error(array('message'=>'Comment not found.'), 404);
  }
  $was_pinned = !empty($comments[$index]['is_pinned']);
  foreach ($comments as &$c) { $c['is_pinned'] = false; }
  unset($c);
  if (!$was_pinned) { $comments[$index]['is_pinned'] = true; }
  update_option($option_key, $comments, false);
  wp_send_json_success(array('pinned' => !$was_pinned));
 }
 public function ajax_get_comment_count() {
  $identifier = sanitize_text_field(wp_unslash(isset($_GET['id']) ? $_GET['id'] : (isset($_POST['id']) ? $_POST['id'] : '')));
  if (empty($identifier)) {
   wp_send_json_error(array('message'=>'Missing id.'), 400);
  }
  $option_key = 'mlp_comments_' . substr(preg_replace('/[^a-z0-9_\-]/i', '', $identifier), 0, 80);
  $comments = get_option($option_key, array());
  wp_send_json_success(array('count' => is_array($comments) ? count($comments) : 0));
 }
 public function ajax_edit_comment() {
  if (!isset($_POST['nonce']) || !wp_verify_nonce($_POST['nonce'], 'mlp_comment_nonce')) {
   wp_send_json_error(array('message'=>'Security check failed.'), 403);
  }
  $identifier  = sanitize_text_field(wp_unslash(isset($_POST['id'])        ? $_POST['id']        : ''));
  $index       = isset($_POST['index'])     ? intval($_POST['index'])     : -1;
  $text        = sanitize_textarea_field(wp_unslash(isset($_POST['text'])   ? $_POST['text']      : ''));
  $pub_token   = sanitize_text_field(wp_unslash(isset($_POST['pub_token'])  ? $_POST['pub_token'] : ''));
  $cmt_id_raw  = sanitize_text_field(wp_unslash(isset($_POST['cmt_id'])     ? $_POST['cmt_id']    : ''));
  if (empty($identifier) || $index < 0 || empty(trim($text))) {
   wp_send_json_error(array('message'=>'Missing data.'), 400);
  }
  if (strlen($text) > 500) {
   wp_send_json_error(array('message'=>'Comment too long (max 500 characters).'), 400);
  }
  $is_publisher = (!empty($pub_token) && $pub_token === $this->mlp_pub_token($identifier));
  $option_key   = 'mlp_comments_' . substr(preg_replace('/[^a-z0-9_\-]/i', '', $identifier), 0, 80);
  $comments     = get_option($option_key, array());
  if (!is_array($comments) || !isset($comments[$index])) {
   wp_send_json_error(array('message'=>'Comment not found.'), 404);
  }
  $c = $comments[$index];
  if (!$is_publisher) {
   if (empty($cmt_id_raw) || empty($c['cmt_id_hash'])) {
    wp_send_json_error(array('message'=>'Unauthorized.'), 403);
   }
   $viewer_hash = substr(hash('sha256', $cmt_id_raw . wp_salt()), 0, 32);
   if (!hash_equals($c['cmt_id_hash'], $viewer_hash)) {
    wp_send_json_error(array('message'=>'Unauthorized.'), 403);
   }
  }
  $comments[$index]['text']   = $text;
  $comments[$index]['edited'] = true;
  update_option($option_key, $comments, false);
  wp_send_json_success(array('message'=>'Comment updated.'));
 }
 public function ajax_delete_comment() {
  if (!isset($_POST['nonce']) || !wp_verify_nonce($_POST['nonce'], 'mlp_comment_nonce')) {
   wp_send_json_error(array('message'=>'Security check failed.'), 403);
  }
  $identifier  = sanitize_text_field(wp_unslash(isset($_POST['id'])        ? $_POST['id']        : ''));
  $index       = isset($_POST['index'])     ? intval($_POST['index'])     : -1;
  $pub_token   = sanitize_text_field(wp_unslash(isset($_POST['pub_token'])  ? $_POST['pub_token'] : ''));
  $cmt_id_raw  = sanitize_text_field(wp_unslash(isset($_POST['cmt_id'])     ? $_POST['cmt_id']    : ''));
  if (empty($identifier) || $index < 0) {
   wp_send_json_error(array('message'=>'Missing data.'), 400);
  }
  $is_publisher = (!empty($pub_token) && $pub_token === $this->mlp_pub_token($identifier));
  $option_key   = 'mlp_comments_' . substr(preg_replace('/[^a-z0-9_\-]/i', '', $identifier), 0, 80);
  $comments     = get_option($option_key, array());
  if (!is_array($comments) || !isset($comments[$index])) {
   wp_send_json_error(array('message'=>'Comment not found.'), 404);
  }
  if (!$is_publisher) {
   $c = $comments[$index];
   if (empty($cmt_id_raw) || empty($c['cmt_id_hash'])) {
    wp_send_json_error(array('message'=>'Unauthorized.'), 403);
   }
   $viewer_hash = substr(hash('sha256', $cmt_id_raw . wp_salt()), 0, 32);
   if (!hash_equals($c['cmt_id_hash'], $viewer_hash)) {
    wp_send_json_error(array('message'=>'Unauthorized.'), 403);
   }
  }
  unset($comments[$index]);
  $comments = array_values($comments);
  update_option($option_key, $comments, false);
  wp_send_json_success(array('message'=>'Comment deleted.'));
 }
 public function create_share_table() {
global $wpdb;
$table_name = $wpdb->prefix . 'mlp_shared_codes';
$charset_collate = $wpdb->get_charset_collate();
$sql = "CREATE TABLE IF NOT EXISTS $table_name (
 id bigint(20) UNSIGNED NOT NULL AUTO_INCREMENT,
 share_code varchar(100) NOT NULL,
 tab_name varchar(255) NOT NULL,
 tab_data longtext NOT NULL,
 shared_by varchar(100),
 expires_at datetime NOT NULL,
 created_at datetime DEFAULT CURRENT_TIMESTAMP,
 PRIMARY KEY (id),
 UNIQUE KEY share_code (share_code),
 KEY expires_at (expires_at),
 KEY created_at (created_at)
) $charset_collate;";
require_once(ABSPATH . 'wp-admin/includes/upgrade.php');
dbDelta($sql);
 }

 public function enqueue_scripts() {
global $post;
if (is_a($post, 'WP_Post') && has_shortcode($post->post_content, 'mobile_live_preview')) {
 // Preconnect to CDN so TLS + DNS are resolved before the first script request.
 add_action('wp_head', function() {
  echo '<link rel="preconnect" href="https://cdnjs.cloudflare.com" crossorigin>' . "
";
 }, 1);
 wp_enqueue_style('mlp-font-awesome', 'https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css', array(), '6.4.0');
 wp_style_add_data('mlp-font-awesome', 'crossorigin', 'anonymous');
 if (isset(self::$sri_hashes['mlp-font-awesome-css'])) {
 wp_style_add_data('mlp-font-awesome', 'integrity', self::$sri_hashes['mlp-font-awesome-css']);
 }
 // Write plugin CSS to a static cacheable file instead of a large inline
 // <style> block. Browsers and Cloudflare can then cache it at the edge.
 $this->ensure_css_file();
 $css_path = plugin_dir_path(__FILE__) . 'assets/mlp-main.css';
 $css_url  = plugin_dir_url(__FILE__)  . 'assets/mlp-main.css';
 if ( file_exists($css_path) ) {
  wp_enqueue_style('mlp-main-css', $css_url, array(), filemtime($css_path));
 } else {
  // Fallback: inline when filesystem is read-only.
  wp_add_inline_style('mlp-font-awesome', $this->get_styles());
 }
 // Font Awesome icons are only inside the plugin widget — never above the
 // fold — so we can load it non-blocking via the preload trick.
 add_filter('style_loader_tag', function($html, $handle) {
  if ($handle !== 'mlp-font-awesome') return $html;
  $preload = str_replace("rel='stylesheet'", "rel='preload' as='style' onload=\"this.onload=null;this.rel='stylesheet'\"", $html);
  return $preload . '<noscript>' . $html . '</noscript>' . "\n";
 }, 10, 2);
 wp_enqueue_script('jquery');
 // Preprocessor libraries are loaded on-demand (lazy) via JS.
 // We only emit their CDN URLs into the page so the JS loader can fetch
 // whichever one the user actually needs, the first time it is needed.
 add_action('wp_head', function() {
     echo '<script>window.mlpPreprocessorCDN={'
         . '"scss":"https://cdnjs.cloudflare.com/ajax/libs/sass.js/0.11.1/sass.sync.min.js",'
         . '"sass":"https://cdnjs.cloudflare.com/ajax/libs/sass.js/0.11.1/sass.sync.min.js",'
         . '"less":"https://cdnjs.cloudflare.com/ajax/libs/less.js/4.2.0/less.min.js",'
         . '"typescript":"https://cdnjs.cloudflare.com/ajax/libs/typescript/5.3.3/typescript.min.js",'
         . '"jsx":"https://cdnjs.cloudflare.com/ajax/libs/babel-standalone/7.23.5/babel.min.js",'
         . '"babel":"https://cdnjs.cloudflare.com/ajax/libs/babel-standalone/7.23.5/babel.min.js",'
         . '"coffeescript":"https://cdnjs.cloudflare.com/ajax/libs/coffeescript/2.7.0/coffeescript.min.js",'
         . '"pug":"https://cdnjs.cloudflare.com/ajax/libs/pug/3.0.2/pug.min.js",'
         . '"markdown":"https://cdnjs.cloudflare.com/ajax/libs/marked/9.1.6/marked.min.js",'
         . '"livescript":"https://cdnjs.cloudflare.com/ajax/libs/livescript/1.6.1/livescript.min.js"'
         . '};</script>' . "\n";
 }, 5);
}
 }
 /**
  * Write the plugin JS to a static file so Cloudflare and browsers can cache
  * it. Called once at activation and again on the first frontend load if the
  * file is missing (e.g. after a server wipe). Never regenerated mid-life.
  */
 public function ensure_js_file() {
$js_path = plugin_dir_path(__FILE__) . 'assets/mlp-main.js';
$dir = dirname($js_path);
if ( ! is_dir($dir) ) {
 wp_mkdir_p($dir);
}
/* CPU-spike fix: only write the file when it is actually missing or stale.
 * Uses a hash of the plugin PHP file so ANY edit (logo URL, text, etc.)
 * forces an immediate regeneration regardless of filesystem timestamps,
 * which are unreliable after FTP/SFTP uploads that preserve mtime. */
$php_hash      = $this->get_plugin_file_hash();
$hash_path     = $dir . '/mlp-main.hash';
$stored_hash   = file_exists( $hash_path ) ? file_get_contents( $hash_path ) : '';
$js_stale      = ! file_exists( $js_path ) || ( $php_hash !== trim( $stored_hash ) );
if ( $js_stale ) {
 file_put_contents( $js_path, '/* MLP v6.1.2-cpu */' . $this->get_script() );
 file_put_contents( $hash_path, $php_hash );
}
 }
 /**
  * Write the plugin CSS to a static file so browsers and Cloudflare can
  * cache it. Called the first time a page with the shortcode loads (or
  * whenever the plugin PHP file changes — same hash strategy as JS).
  */
 public function ensure_css_file() {
$css_path = plugin_dir_path(__FILE__) . 'assets/mlp-main.css';
$dir = dirname($css_path);
if ( ! is_dir($dir) ) {
 wp_mkdir_p($dir);
}
$php_hash    = $this->get_plugin_file_hash();
$hash_path   = $dir . '/mlp-main-css.hash';
$stored_hash = file_exists($hash_path) ? file_get_contents($hash_path) : '';
$css_stale   = ! file_exists($css_path) || ( $php_hash !== trim($stored_hash) );
if ( $css_stale ) {
 file_put_contents($css_path, '/* MLP v6.1.2-css */' . $this->get_styles());
 file_put_contents($hash_path, $php_hash);
}
 }
 public function output_javascript() {
global $post;
if ( ! is_a($post, 'WP_Post') || ! has_shortcode($post->post_content, 'mobile_live_preview') ) {
 return;
}
// Ensure the static asset exists (written once on first load if missing).
$this->ensure_js_file();
$js_path = plugin_dir_path(__FILE__) . 'assets/mlp-main.js';
$js_url  = plugin_dir_url(__FILE__)  . 'assets/mlp-main.js';
if ( file_exists($js_path) ) {
 // Proper enqueued script — Cloudflare caches at edge, browser caches locally.
 // filemtime() as version busts CDN automatically after re-activation.
 wp_enqueue_script(
  'mlp-main',
  $js_url,
  array('jquery'),
  filemtime($js_path),
  true // Load in footer.
 );
} else {
 // Filesystem is read-only — degrade gracefully to inline via wp_footer.
 add_action('wp_footer', function() {
  echo "\n" . '<script type="text/javascript">/* MLP v6.1.0 (inline fallback) */' . $this->get_script() . '</script>' . "\n";
 }, 100);
}
 }
