 private function get_default_templates() {
// Use a static variable so the large array is only built once per PHP request,
// even if this method is called multiple times during a single request.
static $cache = null;
if ( $cache !== null ) { return $cache; }
$cache = array();
return $cache;
 }
 public function sanitize_templates( $raw ) {
$decoded = json_decode( wp_unslash( $raw ), true );
if ( ! is_array( $decoded ) ) {
 return get_option( 'mlp_code_templates', wp_json_encode( $this->get_default_templates() ) );
}
$clean = array();
foreach ( $decoded as $tpl ) {
 $clean[] = array(
    'id'       => sanitize_text_field( $tpl['id'] ?? '' ),
    'name'     => sanitize_text_field( $tpl['name'] ?? '' ),
    'category' => sanitize_text_field( $tpl['category'] ?? '' ),
    'html'     => wp_unslash( $tpl['html'] ?? '' ),
    'css'      => wp_unslash( $tpl['css'] ?? '' ),
    'js'       => wp_unslash( $tpl['js'] ?? '' ),
    'builtin'  => ! empty( $tpl['builtin'] ),
 );
}
return wp_json_encode( $clean );
 }
 public function ajax_get_templates() {
check_ajax_referer( 'mlp_ajax_nonce', 'nonce' );
$current_ver = 6;
// Serve from object cache when possible — avoids DB reads on every template open.
$cached = wp_cache_get( 'mlp_templates_v' . $current_ver, 'mlp_templates' );
if ( $cached !== false ) {
 wp_send_json_success( $cached );
}
$stored_ver = (int) get_option( 'mlp_tpl_version', 0 );
$raw       = get_option( 'mlp_code_templates', '' );
$templates = $raw ? json_decode( $raw, true ) : null;
if ( ! is_array( $templates ) ) {
 $templates = array();
}
if ( $stored_ver < $current_ver ) {
 // Merge defaults into existing templates without wiping user-added ones.
 // Build a map of existing template IDs so we can skip re-adding built-ins
 // that the user may have edited, while still adding any brand-new defaults.
 $existing_ids = array();
 foreach ( $templates as $t ) {
  if ( ! empty( $t['id'] ) ) {
   $existing_ids[ $t['id'] ] = true;
  }
 }
 foreach ( $this->get_default_templates() as $default ) {
  if ( empty( $existing_ids[ $default['id'] ] ) ) {
   $templates[] = $default;
  }
 }
 $merged_json = wp_json_encode( $templates );
 update_option( 'mlp_code_templates', $merged_json );
 update_option( 'mlp_tpl_version', $current_ver );
}
if ( empty( $templates ) ) {
 $templates = $this->get_default_templates();
 update_option( 'mlp_code_templates', wp_json_encode( $templates ) );
 update_option( 'mlp_tpl_version', $current_ver );
}
wp_cache_set( 'mlp_templates_v' . $current_ver, $templates, 'mlp_templates', 300 );
wp_send_json_success( $templates );
 }
 public function ajax_save_template() {
check_ajax_referer( 'mlp_ajax_nonce', 'nonce' );
if ( ! current_user_can( 'manage_options' ) ) {
 wp_send_json_error( 'Permission denied.' );
}
$raw       = get_option( 'mlp_code_templates', '' );
$templates = $raw ? json_decode( $raw, true ) : $this->get_default_templates();
if ( ! is_array( $templates ) ) {
 $templates = $this->get_default_templates();
}
$id   = sanitize_text_field( $_POST['tpl_id'] ?? '' );
$name = sanitize_text_field( $_POST['tpl_name'] ?? '' );
$cat  = sanitize_text_field( $_POST['tpl_category'] ?? 'Custom' );
$html = wp_unslash( $_POST['tpl_html'] ?? '' );
$css  = wp_unslash( $_POST['tpl_css'] ?? '' );
$js   = wp_unslash( $_POST['tpl_js'] ?? '' );
if ( empty( $name ) ) {
 wp_send_json_error( 'Template name is required.' );
}
$new = array(
   'id'       => $id ? $id : 'tpl_' . uniqid(),
   'name'     => $name,
   'category' => $cat,
   'html'     => $html,
   'css'      => $css,
   'js'       => $js,
   'builtin'  => false,
);
$found = false;
foreach ( $templates as &$tpl ) {
 if ( $tpl['id'] === $new['id'] ) {
 $tpl  = $new;
 $found = true;
 break;
 }
}
unset( $tpl );
if ( ! $found ) {
 $templates[] = $new;
}
update_option( 'mlp_code_templates', wp_json_encode( $templates ) );
wp_cache_delete( 'mlp_templates_v' . 6, 'mlp_templates' );
wp_send_json_success( $templates );
 }
 public function ajax_delete_template() {
check_ajax_referer( 'mlp_ajax_nonce', 'nonce' );
if ( ! current_user_can( 'manage_options' ) ) {
 wp_send_json_error( 'Permission denied.' );
}
$id = sanitize_text_field( $_POST['tpl_id'] ?? '' );
if ( empty( $id ) ) {
 wp_send_json_error( 'Template ID required.' );
}
$raw       = get_option( 'mlp_code_templates', '' );
$templates = $raw ? json_decode( $raw, true ) : $this->get_default_templates();
if ( ! is_array( $templates ) ) {
 $templates = $this->get_default_templates();
}
$templates = array_values( array_filter( $templates, function( $t ) use ( $id ) {
 return $t['id'] !== $id;
} ) );
update_option( 'mlp_code_templates', wp_json_encode( $templates ) );
// Bust the object-cache so ajax_get_templates picks up the deletion immediately.
wp_cache_delete( 'mlp_templates_v' . 6, 'mlp_templates' );
wp_send_json_success( $templates );
 }
 public function shortcode($atts, $content = null) {
// Load all plugin options in one cache-friendly call instead of 7 separate get_option() calls.
$mlp_opts = wp_cache_get( 'mlp_shortcode_opts', 'mlp_options' );
if ( $mlp_opts === false ) {
 $mlp_opts = array(
  'height'       => get_option('mlp_default_height', '600px'),
  'theme'        => get_option('mlp_default_theme', 'dark'),
  'editor_theme' => get_option('mlp_editor_theme', 'vs-dark'),
  'title'        => get_option('mlp_default_title', 'Mobile Live Preview'),
  'html'         => get_option('mlp_default_html', "<!DOCTYPE html>\n<html>\n<title>HTML Tutorial</title>\n<body>\n<h1>This is a heading</h1>\n<p>This is a paragraph.</p>\n</body>\n</html>"),
  'css'          => get_option('mlp_default_css', ''),
  'js'           => get_option('mlp_default_js', ''),
 );
 wp_cache_set( 'mlp_shortcode_opts', $mlp_opts, 'mlp_options', 300 );
}
$atts = shortcode_atts(array(
   'height'       => $mlp_opts['height'],
   'theme'        => $mlp_opts['theme'],
   'editor_theme' => $mlp_opts['editor_theme'],
   'default_html' => '',
   'default_css'  => '',
   'default_js'   => '',
   'title'        => $mlp_opts['title'],
), $atts, 'mobile_live_preview');
static $mlp_instance_counter = 0;
$mlp_instance_counter++;
$mlp_post_id = get_the_ID();
if (!$mlp_post_id) {
    // Fallback: use a hash of the page URL path only (no query string)
    $mlp_post_id = 'p' . abs(crc32(parse_url($_SERVER['REQUEST_URI'] ?? '/', PHP_URL_PATH) ?? '/'));
}
$instance_id = 'mlp-' . $mlp_post_id . '-' . $mlp_instance_counter;
$saved_html = $mlp_opts['html'];
$saved_css  = $mlp_opts['css'];
$saved_js   = $mlp_opts['js'];
$default_html = !empty($atts['default_html']) ? $atts['default_html'] : $saved_html;
$default_css = !empty($atts['default_css']) ? $atts['default_css'] : $saved_css;
$default_js = !empty($atts['default_js']) ? $atts['default_js'] : $saved_js;
$original_defaults = array(
   'html' => $default_html,
   'css' => $default_css,
   'js' => $default_js
);
if (empty($default_html) && empty($default_css) && empty($default_js)) {
 $default_html = '<!DOCTYPE html>
<html>
<title>HTML Tutorial</title>
<body>
<h1>This is a heading</h1>
<p>This is a paragraph.</p>
</body>
</html>';
 $default_css = '';
 $default_js = '';
 $original_defaults = array(
    'html' => $default_html,
    'css' => $default_css,
    'js' => $default_js
 );
}
ob_start();
