<!-- ════════════════════════════════════════════════════════════════════
     /PTEROCOS REDESIGN — original .mlp-header now starts (kept hidden)
     ════════════════════════════════════════════════════════════════════ -->
<div class="mlp-header">
<img src="http://pterocos.eu.org/wp-content/uploads/2026/04/Logo_numerique_de_pterocos.eu_.org-removebg-preview.png" alt="Logo" class="mlp-header-logo" />
<h1 id="mlp-header-title" style="white-space:nowrap;overflow:hidden;text-overflow:ellipsis;max-width:100%;">Beta</h1>
<script>
(function(){
  function getCurrentProjectName(){
    var projName = '';
    try {
      var projId = window.mlpCurrentProjectId;
      if(projId){
        var raw = localStorage.getItem('mlp_projects');
        if(raw){
          var projects = JSON.parse(raw);
          for(var i=0;i<projects.length;i++){
            if(projects[i].id===projId){ projName = projects[i].name||''; break; }
          }
        }
      }
    } catch(e){}
    return projName;
  }
  function updateBrandLabels(projName){
    var label = projName || 'Untitled Project';
    var nodes = document.getElementsByClassName('ptr-project-name');
    for(var i=0;i<nodes.length;i++){
      if(nodes[i].textContent !== label){
        nodes[i].textContent = label;
      }
      if(nodes[i].getAttribute('title') !== label){
        nodes[i].setAttribute('title', label);
      }
    }
  }
  function updateHeaderTitle(){
    var projName = getCurrentProjectName();
    updateBrandLabels(projName);
    var h1 = document.getElementById('mlp-header-title');
    if(!h1) return;
    var tabName = '';
    // Get active tab name
    try {
      if(window.monacoInstances){
        var keys = Object.keys(window.monacoInstances);
        for(var k=0;k<keys.length;k++){
          var inst = window.monacoInstances[keys[k]];
          if(inst && inst.activeTabId && inst.tabs && inst.tabs[inst.activeTabId]){
            tabName = inst.tabs[inst.activeTabId].title||'';
            break;
          }
        }
      }
    } catch(e){}
    if(projName && tabName){
      h1.textContent = projName + ' \u2192 ' + tabName;
    } else if(projName){
      h1.textContent = projName;
    } else if(tabName){
      h1.textContent = tabName;
    } else {
      h1.textContent = 'Beta';
    }
  }
  // Run after a short delay to ensure everything is initialized
  setTimeout(updateHeaderTitle, 500);
  setTimeout(updateHeaderTitle, 1500);
  // Also update on tab switch and project load
  var _origLoadProject = window.mlpLoadProject;
  window.mlpLoadProject = function(p){
    if(typeof _origLoadProject === 'function') _origLoadProject.apply(this, arguments);
    setTimeout(updateHeaderTitle, 300);
  };
  // Poll for tab changes
  setInterval(updateHeaderTitle, 2000);
})();
</script>
