<script>
(function(){
  var iid = '<?php echo esc_js($instance_id); ?>';
  var wrap = document.getElementById('mlp-bar-backups-dropdown-wrap-'+iid);
  var btn = wrap ? wrap.querySelector('.mlp-bar-backups-dropdown-btn') : null;
  var menu = document.getElementById('mlp-bar-backups-dropdown-menu-'+iid);
  if(!wrap || !btn || !menu) return;
  btn.addEventListener('click', function(e){
    e.preventDefault(); e.stopPropagation();
    var isOpen = menu.style.display === 'block';
    document.querySelectorAll('.mlp-bar-backups-dropdown-menu').forEach(function(m){ m.style.display = 'none'; });
    if(!isOpen) menu.style.display = 'block';
  });
  menu.querySelectorAll('button').forEach(function(b){
    b.addEventListener('click', function(){ menu.style.display = 'none'; });
  });
  document.addEventListener('click', function(e){
    if(!wrap.contains(e.target)) menu.style.display = 'none';
  });
})();
</script>
