<!-- Wire per-panel fullscreen buttons → opens fullscreen editor, then switches to the clicked language tab.
     Wire per-panel gear buttons → opens the preprocessor popup for that language.
     Wire topbar Settings button → opens the existing Settings menu (delegates to .mlp-editor-settings-gear). -->
<!-- Topbar Settings popup styles (self-contained — does not touch existing gear menu CSS) -->
<style>
.ptr-settings-modal-backdrop{position:fixed;inset:0;background:rgba(0,0,0,0.65);z-index:999998;display:none;align-items:center;justify-content:center;animation:ptr-settings-fade 0.15s ease;}
.ptr-settings-modal-backdrop.open{display:flex;}
.ptr-settings-modal{background:#0c0c0c;border:1px solid #444;min-width:300px;max-width:92vw;box-shadow:0 20px 50px rgba(0,0,0,0.9);font-family:'Consolas','Monaco','Courier New',monospace;color:#e6e6e6;animation:ptr-settings-pop 0.18s ease;}
.ptr-settings-modal-header{display:flex;align-items:center;gap:8px;padding:12px 16px;border-bottom:1px solid #1a1a1a;background:#0a0a0a;}
.ptr-settings-modal-dot{width:8px;height:8px;border-radius:50%;background:#4dccff;box-shadow:0 0 6px rgba(77,204,255,0.7);}
.ptr-settings-modal-title{flex:1;font-size:0.78rem;color:#fff;text-transform:uppercase;letter-spacing:0.08em;font-weight:600;}
.ptr-settings-modal-close{background:none;border:none;color:#888;cursor:pointer;font-size:0.9rem;padding:4px 6px;line-height:1;}
.ptr-settings-modal-close:hover{color:#fff;}
.ptr-settings-modal-body{padding:8px 0;display:flex;flex-direction:column;}
.ptr-settings-modal-item{display:flex;align-items:center;gap:12px;padding:12px 18px;background:transparent;border:none;color:#e6e6e6;font-family:inherit;font-size:0.82rem;cursor:pointer;text-align:left;width:100%;transition:background 0.12s,color 0.12s;}
.ptr-settings-modal-item:hover{background:#1e1e1e;color:#fff;}
.ptr-settings-modal-item i{font-size:0.95rem;width:18px;text-align:center;}
@keyframes ptr-settings-fade{from{opacity:0;}to{opacity:1;}}
@keyframes ptr-settings-pop{from{opacity:0;transform:translateY(-6px) scale(0.98);}to{opacity:1;transform:none;}}
</style>
<script>
(function(){
  var iid = <?php echo wp_json_encode($instance_id); ?>;
  /* Wait for jQuery + DOM ready (some themes load jQuery in the footer). */
  function whenReady(cb){
    if (window.jQuery && document.readyState !== "loading") { window.jQuery(cb); return; }
    if (window.jQuery) { window.jQuery(function($){ cb($); }); return; }
    setTimeout(function(){ whenReady(cb); }, 50);
  }
  whenReady(function($){
    /* Move the existing Settings wrap (which holds the Ptero/Editor sub-panels) out of any
       hidden ancestor into <body> so its position:fixed sub-panels can actually paint when the
       existing handlers open them. Hide its original gear span — the topbar Settings button + the
       new popup replace the inline gear UI. All existing handlers continue to work because they
       are document-delegated on .mlp-gear-menu-btn / .mlp-gear-panel. */
    (function relocateSettingsWrap(){
      var $w = $(".mlp-editor-settings-wrap[data-instance='"+iid+"']").not(".mlp-fs-gear-wrap").first();
      if (!$w.length || $w.data("ptrRelocated")) return;
      $w.appendTo("body").css({position:"absolute", top:"-9999px", left:"-9999px", margin:0, width:"0", height:"0", overflow:"visible"});
      $w.children(".mlp-editor-settings-gear").hide();
      $w.data("ptrRelocated", true);
    })();

    /* Per-panel "open in fullscreen" buttons. */
    $(document).off("click.ptrPanelFs-"+iid).on("click.ptrPanelFs-"+iid, "#"+iid+" .ptr-panel-fs-btn", function(e){
      e.preventDefault(); e.stopPropagation();
      var tab = $(this).data("tab") || "html";
      try {
        if (typeof window.openFullscreenEditor === "function") { window.openFullscreenEditor(iid); }
        setTimeout(function(){
          if (typeof window.switchFullscreenEditorTab === "function") { window.switchFullscreenEditorTab(iid, tab); }
        }, 60);
      } catch(err){ /* silent */ }
    });

    /* Per-panel gear → preprocessor popup for that language (HTML / CSS / JS). */
    $(document).off("click.ptrPanelGear-"+iid).on("click.ptrPanelGear-"+iid, "#"+iid+" .ptr-panel-gear-btn", function(e){
      e.preventDefault(); e.stopPropagation();
      var lang = $(this).data("tab") || "html";
      try {
        if (typeof window.openPreprocessorModal === "function") { window.openPreprocessorModal(iid, lang); }
      } catch(err){ /* silent */ }
    });

    /* Build the topbar Settings popup once, append to body, and wire its events. */
    function buildSettingsPopup(){
      var existing = document.getElementById("ptr-settings-modal-"+iid);
      if (existing) return existing;
      var html =
        '<div class="ptr-settings-modal-backdrop" id="ptr-settings-modal-'+iid+'" data-instance="'+iid+'">' +
          '<div class="ptr-settings-modal" role="dialog" aria-label="Settings">' +
            '<div class="ptr-settings-modal-header">' +
              '<span class="ptr-settings-modal-dot"></span>' +
              '<span class="ptr-settings-modal-title">Settings</span>' +
              '<button type="button" class="ptr-settings-modal-close" aria-label="Close">&times;</button>' +
            '</div>' +
            '<div class="ptr-settings-modal-body">' +
              '<button type="button" class="ptr-settings-modal-item" data-panel="ptero">' +
                '<i class="fas fa-paint-brush" style="color:#f59e0b;"></i> Ptero Appearance' +
              '</button>' +
              '<button type="button" class="ptr-settings-modal-item" data-panel="editor">' +
                '<i class="fas fa-sliders-h" style="color:#a78bfa;"></i> Editor Appearance' +
              '</button>' +
            '</div>' +
          '</div>' +
        '</div>';
      var wrapper = document.createElement("div");
      wrapper.innerHTML = html;
      var node = wrapper.firstElementChild;
      document.body.appendChild(node);
      return node;
    }

    function openSettingsPopup(){
      var modal = buildSettingsPopup();
      modal.classList.add("open");
    }
    function closeSettingsPopup(){
      var modal = document.getElementById("ptr-settings-modal-"+iid);
      if (modal) modal.classList.remove("open");
    }

    /* Topbar Settings button → opens our popup. */
    $(document).off("click.ptrTopbarSettings-"+iid).on("click.ptrTopbarSettings-"+iid, "#"+iid+" .ptr-topbar-settings-btn", function(e){
      e.preventDefault(); e.stopPropagation();
      openSettingsPopup();
    });

    /* Close button + click on backdrop. */
    $(document).off("click.ptrSettingsClose-"+iid).on("click.ptrSettingsClose-"+iid, "#ptr-settings-modal-"+iid+" .ptr-settings-modal-close", function(e){
      e.preventDefault(); e.stopPropagation();
      closeSettingsPopup();
    });
    $(document).off("click.ptrSettingsBackdrop-"+iid).on("click.ptrSettingsBackdrop-"+iid, "#ptr-settings-modal-"+iid, function(e){
      if (e.target === this) closeSettingsPopup();
    });

    /* Popup item → close popup, then trigger the matching existing menu button so the existing
       Ptero / Editor sub-panel opens with all of its current functionality. */
    $(document).off("click.ptrSettingsItem-"+iid).on("click.ptrSettingsItem-"+iid, "#ptr-settings-modal-"+iid+" .ptr-settings-modal-item", function(e){
      e.preventDefault(); e.stopPropagation();
      var panel = $(this).data("panel");
      closeSettingsPopup();
      var $orig = $(".mlp-gear-menu-btn[data-panel='"+panel+"'][data-instance='"+iid+"']").first();
      if ($orig.length) {
        setTimeout(function(){ $orig.trigger("click"); }, 60);
      }
    });
  });
})();
</script>
<!-- Action dropdown hover styles -->
<style>
/* Trigger button — all states */
.mlp-action-dd-btn,.mlp-action-dd-btn:hover,.mlp-action-dd-btn:focus,.mlp-action-dd-btn:active,.mlp-action-dd-btn:focus-visible{color:#cbd5e1!important;outline:none!important;box-shadow:none!important;}
.mlp-action-dd-btn:hover{background:rgba(255,255,255,0.11)!important;border-color:rgba(255,255,255,0.2)!important;color:#e2e8f0!important;}
.mlp-action-dd-btn:hover .fa-sliders-h{color:#94a3b8!important;}
/* All items — kill browser button default color override on every state */
.mlp-action-dd-item,.mlp-action-dd-item:hover,.mlp-action-dd-item:focus,.mlp-action-dd-item:active,.mlp-action-dd-item:focus-visible{outline:none!important;box-shadow:none!important;-webkit-appearance:none!important;}
.mlp-action-dd-menu button::-moz-focus-inner{border:0!important;}
/* Create Backup */
.mlp-action-dd-item.mlp-create-backup-btn,.mlp-action-dd-item.mlp-create-backup-btn:hover,.mlp-action-dd-item.mlp-create-backup-btn:focus,.mlp-action-dd-item.mlp-create-backup-btn:active{color:#94a3b8!important;background:transparent!important;}
.mlp-action-dd-item.mlp-create-backup-btn:hover{background:rgba(78,201,176,0.07)!important;color:#4ec9b0!important;}
.mlp-action-dd-item.mlp-create-backup-btn:hover span{color:#4ec9b0!important;}
/* Delete Code */
.mlp-action-dd-item.mlp-action-delete-code,.mlp-action-dd-item.mlp-action-delete-code:hover,.mlp-action-dd-item.mlp-action-delete-code:focus,.mlp-action-dd-item.mlp-action-delete-code:active{color:#94a3b8!important;background:transparent!important;}
.mlp-action-dd-item.mlp-action-delete-code:hover{background:rgba(252,165,165,0.07)!important;color:#fca5a5!important;}
.mlp-action-dd-item.mlp-action-delete-code:hover span{color:#fca5a5!important;}
/* Use Default */
.mlp-action-dd-item.mlp-action-use-default,.mlp-action-dd-item.mlp-action-use-default:hover,.mlp-action-dd-item.mlp-action-use-default:focus,.mlp-action-dd-item.mlp-action-use-default:active{color:#94a3b8!important;background:transparent!important;}
.mlp-action-dd-item.mlp-action-use-default:hover{background:rgba(253,230,138,0.07)!important;color:#fde68a!important;}
.mlp-action-dd-item.mlp-action-use-default:hover span{color:#fde68a!important;}
