<script>
/* ════════════════════════════════════════════════════════════════════
   PTEROCOS sidebar wiring — link sidebar buttons to existing controls
   and force Monaco to re-layout for the new 3-column CodePen layout.
   ════════════════════════════════════════════════════════════════════ */
(function(){
  var iid = '<?php echo esc_js($instance_id); ?>';
  var root = document.getElementById(iid);
  if (!root) return;

  // Sidebar toggle
  var toggleBtn = root.querySelector('.ptr-sidebar-toggle');
  if (toggleBtn) {
    toggleBtn.addEventListener('click', function(){
      root.classList.toggle('ptr-sidebar-collapsed');
      // After layout shift, ask Monaco to relayout
      setTimeout(relayoutMonaco, 220);
    });
  }

  // Wire each sidebar action to the existing in-page button
  function clickFirst(selectors){
    for (var i = 0; i < selectors.length; i++) {
      var el = root.querySelector(selectors[i]);
      if (el) { el.click(); return true; }
    }
    return false;
  }
  var actions = {
    'editor': function(){ /* already on editor — scroll to top */
      var sec = root.querySelector('.mlp-editor-section');
      if (sec) sec.scrollIntoView({behavior:'smooth', block:'start'});
    },
    'preview': function(){
      var sec = root.querySelector('.mlp-preview-section');
      if (sec) sec.scrollIntoView({behavior:'smooth', block:'start'});
    },
    'insert-media': function(){
      if (typeof window.mlpMediaOpen === 'function') {
        window.mlpMediaOpen(iid);
      } else {
        clickFirst(['.mlp-manager-media-btn']);
      }
    },
    'backups': function(){ clickFirst(['.mlp-backups-btn', '.mlp-manager-load-backups-btn']); },
    'fullscreen-preview': function(){ clickFirst(['.mlp-fullscreen-preview-button']); },
    'readme': function(){ clickFirst(['.mlp-create-readme-button']); },
    'fullscreen-editor': function(){ clickFirst(['.mlp-fullscreen-editor-btn']); }
  };
  root.querySelectorAll('.ptr-sidebar-link').forEach(function(link){
    link.addEventListener('click', function(e){
      e.preventDefault();
      var act = link.getAttribute('data-ptr-action');
      // Visual active state — keep "editor" pinned active when its action runs
      root.querySelectorAll('.ptr-sidebar-link').forEach(function(l){ l.classList.remove('active'); });
      if (act === 'editor' || act === 'preview') {
        link.classList.add('active');
      } else {
        // Tools just trigger — keep editor active visually
        var ed = root.querySelector('.ptr-sidebar-link[data-ptr-action="editor"]');
        if (ed) ed.classList.add('active');
      }
      var fn = actions[act];
      if (typeof fn === 'function') fn();
    });
  });

  // "Back to Projects" button — reopens the full-page projects manager
  // (mlp-projects.php exposes window.mlpProjectsOpen as the public API).
  root.querySelectorAll('.ptr-back-to-projects').forEach(function(btn){
    btn.addEventListener('click', function(e){
      e.preventDefault();
      try {
        // Snapshot current tabs into the active project before leaving the editor.
        if (typeof window.mlpSyncTabsToProject === 'function') {
          window.mlpSyncTabsToProject();
        }
      } catch(err){}
      if (typeof window.mlpProjectsOpen === 'function') {
        window.mlpProjectsOpen();
      } else {
        // Fallback — directly toggle the overlay if the public API isn't loaded.
        var overlay = document.getElementById('mlp-projects-overlay');
        if (overlay) {
          overlay.classList.remove('mlp-proj-hidden');
          overlay.style.display = '';
          document.body.style.overflow = 'hidden';
        }
      }
    });
  });

  // Force Monaco to re-layout once all 3 editors are visible at once.
  function relayoutMonaco(){
    try {
      if (window.monacoInstances) {
        var keys = Object.keys(window.monacoInstances);
        for (var k = 0; k < keys.length; k++) {
          var inst = window.monacoInstances[keys[k]];
          if (!inst) continue;
          ['html','css','js'].forEach(function(t){
            var ed = inst[t + 'Editor'] || (inst.editors && inst.editors[t]);
            if (ed && typeof ed.layout === 'function') {
              try { ed.layout(); } catch(e){}
            }
          });
        }
      }
      // Fallback: dispatch a window resize so Monaco's resize observer fires
      window.dispatchEvent(new Event('resize'));
    } catch(e){}
  }
  // Run several times during initialization since Monaco loads async
  setTimeout(relayoutMonaco, 400);
  setTimeout(relayoutMonaco, 1200);
  setTimeout(relayoutMonaco, 2500);
  window.addEventListener('resize', relayoutMonaco);
})();
</script>
</div>
<script>
if (typeof window.monacoLoaders === "undefined") {
window.monacoLoaders = [];
}
window.monacoLoaders.push({
instanceId: "<?php echo esc_js($instance_id); ?>",
html: <?php echo wp_json_encode($default_html); ?>,
css: <?php echo wp_json_encode($default_css); ?>,
js: <?php echo wp_json_encode($default_js); ?>,
editorTheme: "<?php echo esc_js($atts['editor_theme']); ?>",
originalDefaults: <?php echo wp_json_encode($original_defaults); ?>,
preprocessors: { html: "html", css: "css", js: "javascript" }
});
// Hard-refresh (Ctrl+F5) safety net: scripts may load out-of-order when cache is bypassed.
// After full page load, check each loader entry and re-trigger init if Monaco didn't mount.
window.addEventListener('load', function() {
  setTimeout(function() {
    if (!window.monacoLoaders || !window.monacoLoaders.length) return;
    window.monacoLoaders.forEach(function(loaderData) {
      var inst = window.monacoInstances && window.monacoInstances[loaderData.instanceId];
      var editorMissing = !inst || !inst.htmlEditor;
      if (editorMissing && typeof initMonacoForInstance === 'function') {
        console.log('[MLP] Hard-refresh recovery: re-initialising', loaderData.instanceId);
        initMonacoForInstance(loaderData);
      }
    });
  }, 600);
});
</script>
