<script>
(function($){
var ajaxurl = '<?php echo esc_js(admin_url('admin-ajax.php')); ?>';
var nonce = '<?php echo esc_js(wp_create_nonce('mlp_ajax_nonce')); ?>';
$(document).on('click', '.mlp-admin-tpl-edit', function(){
var d = $(this).data();
$('#mlp-admin-tpl-id').val(d.id);
$('#mlp-admin-tpl-name').val(d.name);
$('#mlp-admin-tpl-cat').val(d.cat);
$('#mlp-admin-tpl-html').val(d.html);
$('#mlp-admin-tpl-css').val(d.css);
$('#mlp-admin-tpl-js').val(d.js);
$('html,body').animate({scrollTop: $('#mlp-admin-tpl-add-wrap').offset().top - 40}, 300);
$('#mlp-admin-tpl-name').focus();
$('#mlp-admin-tpl-save-btn').text('<?php echo esc_js(__('Update Template', 'mobile-live-preview')); ?>');
});
$('#mlp-admin-tpl-reset-btn').on('click', function(){
$('#mlp-admin-tpl-id').val('');
$('#mlp-admin-tpl-name,#mlp-admin-tpl-cat,#mlp-admin-tpl-html,#mlp-admin-tpl-css,#mlp-admin-tpl-js').val('');
$('#mlp-admin-tpl-save-btn').text('<?php echo esc_js(__('Save Template', 'mobile-live-preview')); ?>');
$('#mlp-admin-tpl-msg').hide();
});
$('#mlp-admin-tpl-form').on('submit', function(e){
e.preventDefault();
var $btn = $('#mlp-admin-tpl-save-btn').prop('disabled', true).text('Saving...');
var $msg = $('#mlp-admin-tpl-msg').hide();
$.post(ajaxurl, {
action: 'mlp_save_template',
nonce: nonce,
tpl_id: $('#mlp-admin-tpl-id').val(),
tpl_name: $('#mlp-admin-tpl-name').val(),
tpl_category: $('#mlp-admin-tpl-cat').val() || 'Custom',
tpl_html: $('#mlp-admin-tpl-html').val(),
tpl_css: $('#mlp-admin-tpl-css').val(),
tpl_js: $('#mlp-admin-tpl-js').val()
}, function(res){
if (res && res.success) {
$msg.text('✓ Saved!').css('color','#4ec9b0').show();
rebuildTable(res.data);
$('#mlp-admin-tpl-reset-btn').trigger('click');
} else {
$msg.text('Error: ' + ((res && res.data) ? res.data : 'Unknown')).css('color','#d16969').show();
}
}).fail(function(){ $msg.text('Server error.').css('color','#d16969').show(); })
.always(function(){ $btn.prop('disabled',false).text('<?php echo esc_js(__('Save Template', 'mobile-live-preview')); ?>'); });
});
$(document).on('click', '.mlp-admin-tpl-delete', function(){
var id = $(this).data('id');
var name = $(this).data('name');
if (!confirm('Delete template "' + name + '"? This cannot be undone.')) return;
var $btn = $(this).prop('disabled', true);
$.post(ajaxurl, { action: 'mlp_delete_template', nonce: nonce, tpl_id: id }, function(res){
if (res && res.success) {
rebuildTable(res.data);
} else { alert('Error deleting template.'); }
}).fail(function(){ alert('Server error.'); })
.always(function(){ $btn.prop('disabled',false); });
});
function esc(s){ return $('<div>').text(String(s||'')).html(); }
function rebuildTable(templates){
var $tbody = $('#mlp-admin-tpl-tbody').empty();
$('#mlp-admin-tpl-count').text(templates.length);
templates.forEach(function(tpl){
var langs = '';
if (tpl.html) langs += '<span style="color:#e34c26;margin-right:4px;">HTML</span>';
if (tpl.css) langs += '<span style="color:#264de4;margin-right:4px;">CSS</span>';
if (tpl.js) langs += '<span style="color:#f7df1e;">JS</span>';
var badge = tpl.builtin
? '<span style="background:rgba(77,204,255,0.12);border:1px solid rgba(77,204,255,0.25);border-radius:10px;font-size:0.65rem;padding:2px 8px;color:#4dccff;">Built-in</span>'
: '<span style="background:rgba(167,139,250,0.12);border:1px solid rgba(167,139,250,0.25);border-radius:10px;font-size:0.65rem;padding:2px 8px;color:#a78bfa;">Custom</span>';
