function performCodeAnalysis(code, language, type) {const lines=code.split("\n").length;const suggestions=[];let complexity=0;if (type === "html") {complexity += (code.match(/<div/g) || []).length*2;
complexity += (code.match(/<script/g) || []).length*5;complexity += (code.match(/<style/g) || []).length*3;if (!code.includes("<!DOCTYPE")) {suggestions.push({type: "best-practice",title: "Missing DOCTYPE",description: "Add <!DOCTYPE html> at the beginning for proper rendering.",icon: "🏷️"});}
if ((code.match(/<div/g) || []).length>10) {suggestions.push({type: "performance",title: "Too many divs",description: "Consider using semantic HTML5 elements like <header>, <main>, <section>.",icon: "⚡"});}
if (!code.includes("viewport")) {suggestions.push({type: "suggestion",title: "Missing Viewport Meta Tag",description: "Add <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\"> for better mobile responsiveness.",icon: "📱"});}
if (code.includes("<table")) {suggestions.push({type: "accessibility",title: "Table Accessibility",description: "Consider adding <caption> and scope attributes for better screen reader support.",
icon: "♿"});}} else if (type === "css") {complexity += (code.match(/{/g) || []).length;complexity += (code.match(/@media/g) || []).length*3;if (!code.includes("box-sizing")) {suggestions.push({
type: "best-practice",title: "Consider Box-Sizing",description: "Add*{ box-sizing: border-box;}for more predictable layouts.",icon: "📦"});}
if ((code.match(/!important/g) || []).length>3) {suggestions.push({type: "performance",title: "Too many !important",description: "Overusing !important makes CSS hard to maintain. Try to increase specificity instead.",icon: "⚠️"});}
if (code.includes("px") && lines>20) {suggestions.push({type: "suggestion",title: "Consider using relative units",description: "Replace px with em/rem/vh/vw for better responsiveness.",icon: "📏"});}
if (!code.includes("@media")) {suggestions.push({type: "accessibility",title: "Missing Media Queries",description: "Add media queries for better responsive design on different screen sizes.",
icon: "📱"});}} else if (type === "js") {complexity += (code.match(/function/g) || []).length*3;complexity += (code.match(/if\s*\(/g) || []).length*2;
complexity += (code.match(/for\s*\(/g) || []).length*2;if (!code.includes("use strict")) {suggestions.push({type: "best-practice",title: "Missing use strict",description: "Add use strict; at the beginning to catch common coding mistakes.",icon: "🔒"});}
if ((code.match(/var /g) || []).length>0) {suggestions.push({type: "performance",title: "Use const/let instead of var",description: "Replace var with const or let for better scoping and predictability.",icon: "🔄"});}
if (code.includes("== ") || code.includes("== ")) {suggestions.push({type: "security",title: "Use strict equality",description: "Replace == with === to avoid type coercion issues.",icon: "🔐"});}
if (code.includes("console.log")) {suggestions.push({type: "suggestion",title: "Remove console.log in production",description: "Console statements should be removed in production code.",icon: "🗑️"});}
if (!code.includes("try") && code.includes("fetch(")) {suggestions.push({type: "security",title: "Add error handling",description: "Wrap fetch calls in try/catch blocks for better error handling.",icon: "🛡️"});}}
if (suggestions.length === 0) {if (lines>0) {suggestions.push({type: "best-practice",title: "Good job!",description: "Your code looks clean and follows best practices.",icon: "🎉"});} else {
suggestions.push({type: "suggestion",title: "Empty file",description: "Start writing some code to see analysis!",icon: "✏️"});}}
return {linesOfCode: lines,complexityScore: Math.min(complexity, 100),suggestions: suggestions};}
