function mlpGetActiveTabCode(instanceId){var instances=window.monacoInstances&&window.monacoInstances[instanceId];if(!instances||!instances.activeTabId)return null;saveTabData(instanceId,instances.activeTabId);return instances.tabs[instances.activeTabId]||null;}
function mlpExportZIP(instanceId){
var tab=mlpGetActiveTabCode(instanceId);
if(!tab){alert("No active tab to export.");return false;}
var name=(tab.title||"tab").replace(/[^a-zA-Z0-9_\-]/g,"_");
var files={"index.html":tab.html||"","style.css":tab.css||"","script.js":tab.js||""};
/* ---- proper ZIP builder ---- */
function crc32(bytes){
 var c,crcTable=[];
 for(var n=0;n<256;n++){c=n;for(var k=0;k<8;k++){c=((c&1)?0xEDB88320^(c>>>1):(c>>>1));}crcTable[n]=c;}
 var crc=0xFFFFFFFF;
 for(var i=0;i<bytes.length;i++){crc=crcTable[(crc^bytes[i])&0xFF]^(crc>>>8);}
 return (crc^0xFFFFFFFF)>>>0;
}
function strToBytes(s){
 var out=[];
 for(var i=0;i<s.length;i++){
  var c=s.charCodeAt(i);
  if(c<128){out.push(c);}
  else if(c<2048){out.push(0xC0|(c>>6),0x80|(c&0x3F));}
  else{out.push(0xE0|(c>>12),0x80|((c>>6)&0x3F),0x80|(c&0x3F));}
 }
 return out;
}
function u16(n){return[n&0xFF,(n>>8)&0xFF];}
function u32(n){return[n&0xFF,(n>>8)&0xFF,(n>>16)&0xFF,(n>>24)&0xFF];}
function dosTime(){var d=new Date();return[(d.getSeconds()>>1)|(d.getMinutes()<<5)|(d.getHours()<<11),(d.getDate())|(((d.getMonth()+1))<<5)|(((d.getFullYear()-1980))<<9)];}
var dt=dosTime();
var localHeaders=[],centralDirs=[],offset=0,all=[];
Object.keys(files).forEach(function(fname){
 var fBytes=strToBytes(fname);
 var data=strToBytes(files[fname]);
 var crc=crc32(data);
 var sz=data.length;
 var lh=[0x50,0x4B,0x03,0x04,
  20,0, /* version needed */
  0,0,  /* flags */
  0,0,  /* compression: store */
 ].concat(u16(dt[0])).concat(u16(dt[1]))
  .concat(u32(crc))
  .concat(u32(sz)).concat(u32(sz))
  .concat(u16(fBytes.length)).concat(u16(0));
 lh=lh.concat(fBytes);
 var cd=[0x50,0x4B,0x01,0x02,
  20,0,20,0,  /* versions */
  0,0,        /* flags */
  0,0,        /* compression */
 ].concat(u16(dt[0])).concat(u16(dt[1]))
  .concat(u32(crc))
  .concat(u32(sz)).concat(u32(sz))
  .concat(u16(fBytes.length)).concat(u16(0)).concat(u16(0))
  .concat(u16(0)).concat(u16(0))
  .concat(u32(0))
  .concat(u32(offset));
 cd=cd.concat(fBytes);
 lh.forEach(function(b){all.push(b);});
 data.forEach(function(b){all.push(b);});
 offset+=lh.length+sz;
 localHeaders.push(lh.length+sz);
 centralDirs.push(cd);
});
var cdStart=offset;
centralDirs.forEach(function(cd){cd.forEach(function(b){all.push(b);});});
var cdSize=all.length-cdStart;
var eocd=[0x50,0x4B,0x05,0x06,
 0,0,0,0,
].concat(u16(centralDirs.length)).concat(u16(centralDirs.length))
 .concat(u32(cdSize)).concat(u32(cdStart))
 .concat(u16(0));
eocd.forEach(function(b){all.push(b);});
var blob=new Blob([new Uint8Array(all)],{type:"application/zip"});
var a=document.createElement("a");
a.href=URL.createObjectURL(blob);
a.download=name+".zip";
document.body.appendChild(a);
a.click();
setTimeout(function(){document.body.removeChild(a);URL.revokeObjectURL(a.href);},1000);
return true;
}
