function startFullscreenReadmeExpiryCounter(instanceId, expiresAt, isAlreadyExpired=false) {const expiryEl=$("#mlp-fullscreen-readme-expiry-"+instanceId).find("span");
const expiryContainer=$("#mlp-fullscreen-readme-expiry-"+instanceId);const urlInput=$("#mlp-fullscreen-readme-url-"+instanceId);const copyBtn=$("#mlp-fullscreen-readme-copy-btn-"+instanceId);
const instances=window.monacoInstances[instanceId];if (instances.fullscreenReadmeInterval) {clearInterval(instances.fullscreenReadmeInterval);instances.fullscreenReadmeInterval=null;}
if (isAlreadyExpired) {expiryEl.text("EXPIRED");expiryContainer.addClass("expired");urlInput.val("Expired").addClass("expired");copyBtn.prop("disabled", true);return;}
if (!expiresAt) {expiryEl.text("--:--:--");return;}
const updateCounter=() => {const now=Math.floor(Date.now()/1000);const timeLeft=expiresAt-now;if (timeLeft <= 0) {expiryEl.text("EXPIRED");expiryContainer.addClass("expired");
urlInput.val("Expired").addClass("expired");copyBtn.prop("disabled", true);clearInterval(intervalId);instances.fullscreenReadmeInterval=null;return;}
const hours=Math.floor(timeLeft/3600);const minutes=Math.floor((timeLeft % 3600)/60);const seconds=timeLeft % 60;expiryEl.text(hours.toString().padStart(2, "0")+":" +
