const titleDisplay=isExpired?tabData.title+" (EXPIRED)" : tabData.title;const savedIcon=isSaved?" <span class=\"mlp-tab-saved-icon\" title=\"Saved Tab\"><i class=\"fas fa-save\"></i></span>" : "";const previewHtml=`
