function updateFullscreenTabButtonTexts(instanceId) {const instances=window.monacoInstances[instanceId];if (!instances || !instances.activeTabId || !instances.tabs[instances.activeTabId]) return;
const tabData=instances.tabs[instances.activeTabId];const preprocessors=tabData.preprocessors;const htmlPP=preprocessorConfig.html[preprocessors.html].label;const cssPP=preprocessorConfig.css[preprocessors.css].label;const jsPP=preprocessorConfig.js[preprocessors.js].label;
