function copyFullscreenCode(instanceId) {const instances=window.monacoInstances[instanceId];if (!instances) return;let codeToCopy="";let language="";
const activeTab=instances.fullscreenActiveTab || "html";switch(activeTab) {case "html":if (instances.fullscreenHtmlEditor) {codeToCopy=instances.fullscreenHtmlEditor.getValue();language="HTML";}
break;case "css":if (instances.fullscreenCssEditor) {codeToCopy=instances.fullscreenCssEditor.getValue();language="CSS";}
break;case "js":if (instances.fullscreenJsEditor) {codeToCopy=instances.fullscreenJsEditor.getValue();language="JavaScript";}
break;}
