}).catch(function(err) {console.error("Copy failed:", err);showNotification(instanceId, "Failed to copy code", "error");});} else {const textarea=document.createElement("textarea");
textarea.value=codeToCopy;document.body.appendChild(textarea);textarea.select();try {const successful=document.execCommand("copy");if (successful) {
showNotification(instanceId, language+" code copied to clipboard! ✓", "success");} else {showNotification(instanceId, "Failed to copy code", "error");}} catch (err) {console.error("Copy failed:", err);showNotification(instanceId, "Failed to copy code", "error");}
document.body.removeChild(textarea);}}
