(function() {var MLP_MEDIA_LIBRARY_KEY="mlp_media_library";var MLP_STORAGE_WARN_PCT=80;function mlpGetStorageUsed() {var total=0;try {for (var k in localStorage) {if (localStorage.hasOwnProperty(k)) {total += ((localStorage[k] || "").length+k.length)*2;}}} catch(e) {}
return total;}
function mlpGetStorageBreakdown() {var knownKeys={"mlp_saved_tabs": "Saved Tabs","mlp_backups": "Backups","mlp_media_library": "Media Library","mlp_media_history": "Upload History",
"mlp_fork_data": "Fork Data","mlp_fork_name": "Fork Data","mlp_fork_timestamp": "Fork Data"};var prefixGroups=[{ prefix: "mlp_", label: "Plugin Data" }
];var grouped={};var otherBytes=0;var totalUsed=0;try {for (var i=0; i<localStorage.length; i++) {var k=localStorage.key(i);var val=localStorage.getItem(k) || "";var bytes=(val.length+k.length)*2;
