/* ── Position dropdown like More menu (fixed, below trigger) ── */
function mlpPositionDropdown($trigger,$menu){
  var r=$trigger[0].getBoundingClientRect();
  var mw=$menu.outerWidth()||220;
  var left=r.left;
  if(left+mw>window.innerWidth-10)left=window.innerWidth-mw-10;
  $menu.css({top:(r.bottom+4)+\'px\',left:Math.max(4,left)+\'px\'});
}

