  \'ocean\':{\'h\':\'#041630\',\'m\':\'#041020\',\'s\':\'#031228\',\'l\':\'#041020\',\'b\':\'#031228\'},
  \'purple\':{\'h\':\'#1a0a2e\',\'m\':\'#130820\',\'s\':\'#1e1040\',\'l\':\'#130820\',\'b\':\'#1e1040\'},
  \'forest\':{\'h\':\'#0a1a0a\',\'m\':\'#060f06\',\'s\':\'#0a160a\',\'l\':\'#060f06\',\'b\':\'#0a160a\'},
  \'midnight\':{\'h\':\'#050505\',\'m\':\'#000\',\'s\':\'#080808\',\'l\':\'#000\',\'b\':\'#050505\'},
  \'rose\':{\'h\':\'#1a0010\',\'m\':\'#120008\',\'s\':\'#1e0018\',\'l\':\'#120008\',\'b\':\'#1e0018\'}
};

/* ── Apply ptero themes via injected <style> ── */
function mlpApplyNormalTheme(iid,t){
  var sid=\'mlp-ptero-normal-\'+iid;
  var old=document.getElementById(sid);if(old)old.parentNode.removeChild(old);
  if(!t||t===\'default\')return;
  var v=PTERO_NORMAL_THEMES[t];if(!v)return;
  var css=\'#\'+iid+\' .mlp-header{background:\'+v.h+\'!important;border-bottom-color:\'+v.h+\'!important}#\'+iid+\' .mlp-editor-section{background:\'+v.e+\'!important}#\'+iid+\' .mlp-editor-header-bar{background:\'+v.e+\'!important}#\'+iid+\' .mlp-tabs-system{background:\'+v.t+\'!important}#\'+iid+\' .mlp-footer{background:\'+v.f+\'!important}#\'+iid+\'{background:\'+v.bg+\'!important}#\'+iid+\' .mlp-editor-actions{background:\'+v.e+\'!important}#\'+iid+\' .mlp-backup-bar{background:\'+v.e+\'!important}#\'+iid+\' .mlp-preview-header{background:\'+v.e+\'!important}\';
  var el=document.createElement(\'style\');el.id=sid;el.textContent=css;document.head.appendChild(el);
}
function mlpApplyFullscreenTheme(iid,t){
  var sid=\'mlp-ptero-fs-\'+iid;
  var old=document.getElementById(sid);if(old)old.parentNode.removeChild(old);
  if(!t||t===\'default\')return;
  var v=PTERO_FS_THEMES[t];if(!v)return;
  var s=\'#mlp-fullscreen-editor-overlay-\'+iid;
  var css=s+\' .mlp-fullscreen-editor-header{background:\'+v.h+\'!important}\'+s+\' .mlp-fullscreen-editors-container{background:\'+v.m+\'!important}\'+s+\' .mlp-fullscreen-main{background:\'+v.m+\'!important}\'+s+\' .mlp-fullscreen-editor-content{background:\'+v.m+\'!important}\'+s+\' .mlp-fullscreen-editor-container{background:\'+v.m+\'!important}\'+s+\' .mlp-fullscreen-sidebar{background:\'+v.s+\'!important}\'+s+\' .mlp-fullscreen-lang-bar{background:\'+v.l+\'!important}\'+s+\' .mlp-fullscreen-bottom-bar{background:\'+v.b+\'!important}\'+s+\'{background:\'+v.m+\'!important}\';
  var el=document.createElement(\'style\');el.id=sid;el.textContent=css;document.head.appendChild(el);
}

/* ── Render ptero swatches with glow on active ── */
function mlpRenderPteroUI($wrap,iid,ps){
  $wrap.find(\'.mlp-ptero-theme-btn[data-mode="normal"]\').each(function(){
    var active=$(this).data(\'theme\')===ps.normalTheme;
    var $span=$(this).find(\'span:first\');
    var gradient=$span.css(\'background\')||\'\'
    if(active){
      $(this).css({\'border-color\':\'#f59e0b\',\'box-shadow\':\'0 0 0 2px #f59e0b,0 0 12px rgba(245,158,11,0.6)\',\'opacity\':\'1\'});
      $(this).find(\'span:last\').css(\'color\',\'#f59e0b\');
    } else {
      $(this).css({\'border-color\':\'#333\',\'box-shadow\':\'none\',\'opacity\':\'0.7\'});
      $(this).find(\'span:last\').css(\'color\',\'#aaa\');
    }
  });
  $wrap.find(\'.mlp-ptero-theme-btn[data-mode="fullscreen"]\').each(function(){
    var active=$(this).data(\'theme\')===ps.fullscreenTheme;
    if(active){
      $(this).css({\'border-color\':\'#4dccff\',\'box-shadow\':\'0 0 0 2px #4dccff,0 0 12px rgba(77,204,255,0.6)\',\'opacity\':\'1\'});
      $(this).find(\'span:last\').css(\'color\',\'#4dccff\');
    } else {
      $(this).css({\'border-color\':\'#333\',\'box-shadow\':\'none\',\'opacity\':\'0.7\'});
      $(this).find(\'span:last\').css(\'color\',\'#aaa\');
    }
  });
}

/* ── Toggle slider ── */
function mlpSlider($i){$i.siblings(\'.mlp-settings-toggle-slider\').css(\'background\',$i.prop(\'checked\')?\'#4dccff\':\'#2a2a2a\');}

/* ── Apply editor settings to editors ── */
function mlpApplyEditorSettings(iid,s){
  mlpRegisterCustomThemes();
  var inst=window.monacoInstances&&window.monacoInstances[iid];if(!inst)return;
  var eds=[inst.htmlEditor,inst.cssEditor,inst.jsEditor,inst.fullscreenHtmlEditor,inst.fullscreenCssEditor,inst.fullscreenJsEditor];
  eds.forEach(function(ed){if(!ed)return;try{ed.updateOptions({fontSize:s.fontSize,tabSize:s.tabSize,wordWrap:s.wordWrap?\'on\':\'off\',minimap:{enabled:s.minimap},lineNumbers:s.lineNumbers?\'on\':\'off\',autoClosingBrackets:s.brackets?\'always\':\'never\',formatOnPaste:s.formatPaste,smoothScrolling:s.smoothScroll,renderWhitespace:s.whitespace?\'all\':\'none\',guides:{bracketPairs:s.bracketGuides},cursorStyle:s.cursorStyle});}catch(e){}});
  if(window.monaco)try{window.monaco.editor.setTheme(s.theme);}catch(e){}
}

/* ── Render editor settings UI ── */
function mlpRenderEditorUI($wrap,iid,s){
  $wrap.find(\'.mlp-settings-theme-select\').val(s.theme);
  $wrap.find(\'.mlp-settings-font-val\').text(s.fontSize);
  $wrap.find(\'.mlp-settings-tabsize-select\').val(String(s.tabSize));
  $wrap.find(\'.mlp-settings-cursor-select\').val(s.cursorStyle);
  var map={\'mlp-settings-wrap-toggle\':\'wordWrap\',\'mlp-settings-minimap-toggle\':\'minimap\',\'mlp-settings-lines-toggle\':\'lineNumbers\',\'mlp-settings-brackets-toggle\':\'brackets\',\'mlp-settings-formatpaste-toggle\':\'formatPaste\',\'mlp-settings-smooth-toggle\':\'smoothScroll\',\'mlp-settings-whitespace-toggle\':\'whitespace\',\'mlp-settings-bracketguides-toggle\':\'bracketGuides\'};
  $.each(map,function(cls,key){var $i=$wrap.find(\'.\'+cls);$i.prop(\'checked\',s[key]);mlpSlider($i);});
}

/* ── Read editor settings from UI ── */
function mlpReadEditorUI($wrap){
  return {fontSize:parseInt($wrap.find(\'.mlp-settings-font-val\').text())||14,tabSize:parseInt($wrap.find(\'.mlp-settings-tabsize-select\').val())||4,theme:$wrap.find(\'.mlp-settings-theme-select\').val()||\'vs-dark\',cursorStyle:$wrap.find(\'.mlp-settings-cursor-select\').val()||\'line\',wordWrap:$wrap.find(\'.mlp-settings-wrap-toggle\').prop(\'checked\'),minimap:$wrap.find(\'.mlp-settings-minimap-toggle\').prop(\'checked\'),lineNumbers:$wrap.find(\'.mlp-settings-lines-toggle\').prop(\'checked\'),brackets:$wrap.find(\'.mlp-settings-brackets-toggle\').prop(\'checked\'),formatPaste:$wrap.find(\'.mlp-settings-formatpaste-toggle\').prop(\'checked\'),smoothScroll:$wrap.find(\'.mlp-settings-smooth-toggle\').prop(\'checked\'),whitespace:$wrap.find(\'.mlp-settings-whitespace-toggle\').prop(\'checked\'),bracketGuides:$wrap.find(\'.mlp-settings-bracketguides-toggle\').prop(\'checked\')};
}

/* ── Close all dropdowns ── */
function mlpGearCloseAll(){
  $(\'.mlp-gear-top-menu,.mlp-gear-panel\').hide();
  $(\'.mlp-editor-settings-wrap\').removeClass(\'open\');
  $(\'.mlp-editor-settings-gear i\').css(\'transform\',\'rotate(0deg)\');
}

/* ── Boot instance ── */
function mlpBootInstance(iid){
  var $w=$(\'.mlp-editor-settings-wrap[data-instance="\'+iid+\'"]\');
  var s=mlpLoad(iid);
  mlpRenderEditorUI($w,iid,s);
  var ps=mlpLoadPtero(iid);
  mlpRenderPteroUI($w,iid,ps);
  setTimeout(function(){mlpApplyEditorSettings(iid,s);mlpApplyNormalTheme(iid,ps.normalTheme);mlpApplyFullscreenTheme(iid,ps.fullscreenTheme);},600);
}

$(document).on(\'mlp_editors_ready\',function(e,iid){mlpBootInstance(iid);mlpEnsureBoot(iid);});
$(window).on(\'load\',function(){
  $(\'.mlp-editor-settings-wrap\').each(function(){
    var iid=$(this).data(\'instance\');
    if(!iid)return;
    var $w=$(this);
    var ps=mlpLoadPtero(iid);
    var s=mlpLoad(iid);
    mlpRenderEditorUI($w,iid,s);
    mlpRenderPteroUI($w,iid,ps);
    mlpApplyNormalTheme(iid,ps.normalTheme);
    mlpApplyFullscreenTheme(iid,ps.fullscreenTheme);
    mlpEnsureBoot(iid);
  });
});
function mlpEnsureBoot(iid){
  /* CPU fix v6.1.2: replaced setInterval(250ms, 50 tries) with instant check + one-shot event.
     Old behaviour: up to 50 intervals × 250ms = 12.5s of polling per editor instance on every page load.
     New behaviour: zero idle CPU — applies immediately if Monaco is ready, otherwise waits for the
     mlp_editors_ready jQuery event that Monaco already fires when it finishes loading. */
  var inst=window.monacoInstances&&window.monacoInstances[iid];
  if(inst&&(inst.htmlEditor||inst.cssEditor)){
    var s=mlpLoad(iid);mlpApplyEditorSettings(iid,s);
    var ps=mlpLoadPtero(iid);mlpApplyNormalTheme(iid,ps.normalTheme);mlpApplyFullscreenTheme(iid,ps.fullscreenTheme);
    return;
  }
  /* Editor not ready yet — listen once for the ready event instead of polling every 250 ms */
  $(document).one(\'mlp_editors_ready\',function(e,readyIid){
    if(readyIid!==iid)return;
    var s=mlpLoad(iid);mlpApplyEditorSettings(iid,s);
    var ps=mlpLoadPtero(iid);mlpApplyNormalTheme(iid,ps.normalTheme);mlpApplyFullscreenTheme(iid,ps.fullscreenTheme);
  });
}

/* ── Gear click ── */
$(document).on(\'click\',\'.mlp-editor-settings-gear\',function(e){
  e.stopPropagation();
  var $w=$(this).closest(\'.mlp-editor-settings-wrap\');
  var wasOpen=$w.hasClass(\'open\');
  mlpGearCloseAll();
  if(!wasOpen){
    $w.addClass(\'open\');
    $(this).find(\'i\').css(\'transform\',\'rotate(65deg)\');
    var $menu=$w.find(\'.mlp-gear-top-menu\');
    $menu.css(\'display\',\'flex\');
    mlpPositionDropdown($(this),$menu);
  }
});

