/* ── Per-panel [ ] fullscreen buttons in HTML / CSS / JS column headers.
     Registered inside the IIFE so openFullscreenEditor / switchFullscreenEditorTab
     are reachable directly via lexical scope (no window.* lookup needed). ── */
$(document).on(\'click\',\'.ptr-panel-fs-btn\',function(e){
