});

/* ── Export helpers ── */
function mlpGetPreproExt(type, key) {
  var exts={html:{html:\'html\',pug:\'pug\',markdown:\'md\'},css:{css:\'css\',scss:\'scss\',sass:\'sass\',less:\'less\'},js:{javascript:\'js\',typescript:\'ts\',jsx:\'jsx\',coffeescript:\'coffee\',babel:\'js\',livescript:\'ls\'}};
  return(exts[type]&&exts[type][key])||type;
}

/* ── Export single button ── */
$(document).on(\'click\',\'.mlp-settings-export-btn\',function(e){
  e.stopPropagation();
  var iid=$(this).data(\'instance\');
  mlpGearCloseAll();
  var inst=window.monacoInstances&&window.monacoInstances[iid];
  if(!inst||!inst.activeTabId)return;
  if(typeof saveTabData===\'function\')saveTabData(iid,inst.activeTabId);
  var td=inst.tabs[inst.activeTabId];if(!td)return;
  var pp=td.preprocessors||{html:\'html\',css:\'css\',js:\'javascript\'};
  var tab=inst.activeTab||\'html\';
  var ppKey=pp[tab]||(tab===\'js\'?\'javascript\':tab);
  var ext=mlpGetPreproExt(tab,ppKey);
  var code=tab===\'html\'?td.html:tab===\'css\'?td.css:td.js;
  var fname=((td.emoji||\'\')+\' \'+(td.title||\'tab\')).trim().replace(/[^a-z0-9_\\-\\. ]/gi,\'_\')+\'.\'+ext;
  var blob=new Blob([code||\'\'],{type:\'text/plain\'});
  var a=document.createElement(\'a\');a.href=URL.createObjectURL(blob);a.download=fname;a.click();URL.revokeObjectURL(a.href);
  if(typeof showNotification===\'function\')showNotification(iid,\'Exported ✓\',\'success\');
});

/* ── Export ZIP button ── */
$(document).on(\'click\',\'.mlp-settings-exportzip-btn\',function(e){
  e.stopPropagation();
  var iid=$(this).data(\'instance\');
  mlpGearCloseAll();
  var inst=window.monacoInstances&&window.monacoInstances[iid];
  if(!inst||!inst.activeTabId)return;
  if(typeof saveTabData===\'function\')saveTabData(iid,inst.activeTabId);
  var td=inst.tabs[inst.activeTabId];if(!td)return;
  var pp=td.preprocessors||{html:\'html\',css:\'css\',js:\'javascript\'};
  var htmlExt=mlpGetPreproExt(\'html\',pp.html||\'html\');
  var cssExt=mlpGetPreproExt(\'css\',pp.css||\'css\');
  var jsExt=mlpGetPreproExt(\'js\',pp.js||\'javascript\');
  var files=[
    {name:\'index.\'+htmlExt, data:td.html||\'\'},
    {name:\'style.\'+cssExt,  data:td.css||\'\'},
    {name:\'script.\'+jsExt,  data:td.js||\'\'}
  ];
  var tabName=((td.emoji||\'\')+\' \'+(td.title||\'tab\')).trim().replace(/[^a-z0-9_\\-\\. ]/gi,\'_\');
  /* Build zip manually - no external lib needed */
  function strToU8(str){return new TextEncoder().encode(str);}
  function u32le(n){var b=new Uint8Array(4);new DataView(b.buffer).setUint32(0,n,true);return b;}
  function u16le(n){var b=new Uint8Array(2);new DataView(b.buffer).setUint16(0,n,true);return b;}
  function concat(arrays){var len=arrays.reduce(function(s,a){return s+a.length;},0);var out=new Uint8Array(len);var off=0;arrays.forEach(function(a){out.set(a,off);off+=a.length;});return out;}
  function crc32(data){var t=[];for(var i=0;i<256;i++){var c=i;for(var j=0;j<8;j++)c=c&1?0xEDB88320^(c>>>1):c>>>1;t[i]=c;}var crc=0xFFFFFFFF;for(var k=0;k<data.length;k++)crc=t[(crc^data[k])&0xFF]^(crc>>>8);return(crc^0xFFFFFFFF)>>>0;}
  var localHeaders=[];var centralDir=[];var offset=0;
  files.forEach(function(f){
    var nameBytes=strToU8(f.name);
    var dataBytes=strToU8(f.data);
    var crc=crc32(dataBytes);
    var now=new Date();
    var dosDate=((now.getFullYear()-1980)<<9)|((now.getMonth()+1)<<5)|now.getDate();
    var dosTime=(now.getHours()<<11)|(now.getMinutes()<<5)|(now.getSeconds()>>1);
    /* Local file header */
    var lh=concat([
      new Uint8Array([0x50,0x4B,0x03,0x04]),/* sig */
      u16le(20),/* version */u16le(0),/* flags */u16le(0),/* compression: store */
      u16le(dosTime),u16le(dosDate),
      u32le(crc),u32le(dataBytes.length),u32le(dataBytes.length),
      u16le(nameBytes.length),u16le(0),
      nameBytes,dataBytes
    ]);
    localHeaders.push(lh);
    /* Central directory entry */
    var cd=concat([
      new Uint8Array([0x50,0x4B,0x01,0x02]),/* sig */
      u16le(20),u16le(20),u16le(0),u16le(0),/* versions */
      u16le(dosTime),u16le(dosDate),
