document.addEventListener("visibilitychange", function() {
  if (!document.hidden && window.monacoInstances) {
    Object.keys(window.monacoInstances).forEach(function(iid) {
      var inst = window.monacoInstances[iid];
      if (!inst) return;
      // Layout all normal editors
      [inst.htmlEditor, inst.cssEditor, inst.jsEditor].forEach(function(ed) {
        if (ed) { try { ed.layout(); } catch(e) {} }
      });
      // Layout fullscreen editors too
      [inst.fullscreenHtmlEditor, inst.fullscreenCssEditor, inst.fullscreenJsEditor].forEach(function(ed) {
        if (ed) { try { ed.layout(); } catch(e) {} }
      });
      // On mobile, re-check if editors have zero height and force a re-layout after a tick
      if (window.matchMedia && window.matchMedia(\'(max-width: 767px)\').matches) {
        setTimeout(function() {
          [inst.htmlEditor, inst.cssEditor, inst.jsEditor].forEach(function(ed) {
            if (ed) { try { ed.layout(); } catch(e) {} }
          });
        }, 300);
      }
    });
  }
});

/* ── Global editor keyboard shortcuts ──────────────────────────────────────
   Ctrl+Enter  → Refresh preview
   Ctrl+S      → Save current tab (opens save confirmation)
   Ctrl+Shift+F → Toggle fullscreen editor
   Ctrl+Shift+P → Toggle fullscreen preview
   Alt+1/2/3   → Switch HTML / CSS / JS panel
   Registered in capture phase so it fires before Monaco intercepts. ──── */
document.addEventListener("keydown", function(e) {
  var ctrl = e.ctrlKey || e.metaKey;
  if (!ctrl && !e.altKey) return;

  /* Ctrl+Enter → Refresh preview */
  if (ctrl && !e.shiftKey && !e.altKey && e.key === "Enter") {
    var refreshBtn = document.getElementById("mlp-refresh-btn");
    if (refreshBtn) { e.preventDefault(); refreshBtn.click(); }
    return;
  }

  /* Ctrl+S → Save current tab */
  if (ctrl && !e.shiftKey && !e.altKey && e.key.toLowerCase() === "s") {
    var fsOverlay = document.querySelector(".mlp-fullscreen-editor-overlay.active");
    var saveBtn = fsOverlay
      ? fsOverlay.querySelector(".mlp-fs-lang-save-btn")
      : document.querySelector(".mlp-save-btn");
    if (saveBtn) { e.preventDefault(); saveBtn.click(); }
    return;
  }

  /* Ctrl+Shift+F → Toggle fullscreen editor overlay */
  if (ctrl && e.shiftKey && !e.altKey && e.key.toLowerCase() === "f") {
    var activeOverlay = document.querySelector(".mlp-fullscreen-editor-overlay.active");
    if (activeOverlay) {
      var closeBtn = activeOverlay.querySelector(".mlp-fullscreen-editor-close-btn");
      if (closeBtn) { e.preventDefault(); closeBtn.click(); }
    } else {
      var openBtn = document.querySelector(".mlp-settings-fullscreen-btn");
      if (!openBtn) openBtn = document.querySelector(".ptr-panel-fs-btn");
      if (openBtn) { e.preventDefault(); openBtn.click(); }
    }
    return;
  }

  /* Ctrl+Shift+P → Toggle fullscreen preview */
  if (ctrl && e.shiftKey && !e.altKey && e.key.toLowerCase() === "p") {
    var fsPreviewBtn = document.getElementById("mlp-fs-btn");
    if (fsPreviewBtn) { e.preventDefault(); fsPreviewBtn.click(); }
    return;
  }

  /* Alt+1/2/3 → Switch HTML / CSS / JS code panel */
  if (e.altKey && !ctrl && !e.shiftKey) {
    var panels = { "1": "html", "2": "css", "3": "js" };
    var tabName = panels[e.key];
    if (tabName) {
      e.preventDefault();
      var panelBtn = document.querySelector(".mlp-tab-button-horizontal[data-tab=\"" + tabName + "\"]");
      if (panelBtn) panelBtn.click();
    }
    return;
  }
}, true);

